    CONTAINED_PATH_SEP = "__"


    def _trim_to_distinct_cursor_boundary(
        records: list[dict],
        cursor_field: str,
    ) -> list[dict]:
        """Drop trailing records sharing the boundary cursor value. Same
        semantics as the flat-path helper in ``odata.py`` — duplicated here
        to avoid a circular import. Returns empty list when every record
        shares one cursor; caller decides recoverable vs hard failure."""
        if not records:
            return records
        boundary = records[-1].get(cursor_field)
        trim_idx = len(records)
        while trim_idx > 0 and records[trim_idx - 1].get(cursor_field) == boundary:
            trim_idx -= 1
        return records[:trim_idx]


    # Inside generated OData request URLs the segment separator is always
    # a forward slash (the wire format the spec mandates).
    _URL_SEGMENT_SEP = "/"
    # Cap on path depth. Prevents pathological discovery walks on services
    # with cyclic containment graphs; cycles within the cap are also
    # detected via target-type tracking.
    MAX_CONTAINED_DEPTH = 5


    def join_url(base: str, suffix: str) -> str:
        """Append ``suffix`` to ``base`` with at most one slash."""
        return f"{base}{suffix}" if base.endswith("/") else f"{base}/{suffix}"


    def looks_like_iso8601(s: str) -> bool:
        """Cheap ISO-8601 sniff used by ``odata_literal`` to render bare timestamps."""
        if len(s) < 10 or s[4] != "-" or s[7] != "-":
            return False
        try:
            datetime.fromisoformat(s.replace("Z", "+00:00"))
            return True
        except ValueError:
            return False


    def odata_literal(value: Any) -> str:
        """Render a Python value as an OData v4 literal for $filter."""
        if isinstance(value, datetime):
            return value.isoformat().replace("+00:00", "Z")
        if isinstance(value, date):
            return value.isoformat()
        if isinstance(value, bool):
            return "true" if value else "false"
        if isinstance(value, int | float | Decimal):
            return str(value)
        s = str(value)
        if looks_like_iso8601(s):
            return s
        return "'" + s.replace("'", "''") + "'"


    # Re-export of the EDM namespace prefix used by the main module.
    _NS_EDM = "{http://docs.oasis-open.org/odata/ns/edm}"


    def parse_contained_path(table_name: str) -> list[str] | None:
        """Split double-underscore-delimited path; ``None`` for flat names."""
        if _URL_SEGMENT_SEP in table_name:
            # OData entity-set names cannot contain ``/`` (CSDL allows only
            # letters/digits/underscores), so a slash here always means the
            # caller used the wrong separator. Spell out the fix — the
            # generic "not found" error otherwise buries the cause under a
            # 200-entry "Available:" list.
            suggested = table_name.replace(_URL_SEGMENT_SEP, CONTAINED_PATH_SEP)
            raise ValueError(
                f"Contained-collection table names use {CONTAINED_PATH_SEP!r} "
                f"(double underscore) as the segment separator, not "
                f"{_URL_SEGMENT_SEP!r} — slashes aren't valid in Spark SQL "
                f"identifiers, which the SDP framework uses for view names. "
                f"Rename {table_name!r} to {suggested!r} in the pipeline "
                f"config."
            )
        if CONTAINED_PATH_SEP not in table_name:
            return None
        segments = table_name.split(CONTAINED_PATH_SEP)
        if any(not s for s in segments):
            raise ValueError(
                f"Empty path segment in contained table name {table_name!r}; "
                "expected 'Parent__Child' or 'Parent__Child__Grandchild' form."
            )
        if len(segments) > MAX_CONTAINED_DEPTH:
            raise ValueError(
                f"Contained path {table_name!r} exceeds max depth "
                f"{MAX_CONTAINED_DEPTH} (got {len(segments)})."
            )
        return segments


    def contained_nav_props(entity_type: ET.Element) -> list[tuple[str, str]]:
        """``[(nav_name, target_type_ref), ...]`` for ContainsTarget collection
        nav props declared directly on this type; singletons skipped."""
        out: list[tuple[str, str]] = []
        for np in entity_type.findall(f"{_NS_EDM}NavigationProperty"):
            if (np.get("ContainsTarget") or "").lower() != "true":
                continue
            type_ref = np.get("Type", "")
            if not (type_ref.startswith("Collection(") and type_ref.endswith(")")):
                continue
            out.append((np.get("Name"), type_ref[len("Collection(") : -1]))
        return out


    def fk_column_name(segment: str, pk_name: str) -> str:
        """Default ancestor-FK column name: ``<segment>_<pkname>``.

        The actual column the connector writes may be further disambiguated
        (prefixed with leading underscores) if it collides with a leaf
        property or another FK column. See ``ContainedNavMixin._resolve_fk_columns``.
        """
        return f"{segment}_{pk_name}"


    class ContainedNavMixin:
        """Mixin providing contained-collection support for the OData connector.

        Plug in via ``class ODataLakeflowConnect(LakeflowConnect,
        SupportsNamespaces, ContainedNavMixin):``. All methods duck-type
        against the concrete class for HTTP/URL/metadata helpers.
        """

        def _all_contained_nav_props(self, entity_type: ET.Element) -> list[tuple[str, str]]:
            """Contained nav props on the type and its base chain (closest-
            descendant wins on name collision)."""
            out: dict[str, str] = {}
            for type_el in self._resolve_base_chain(entity_type):
                for name, ref in contained_nav_props(type_el):
                    out.setdefault(name, ref)
            return list(out.items())

        def _enumerate_contained_paths(self, top_level_set: str, namespace: str | None) -> list[str]:
            """BFS contained nav-property graph; cap at MAX_CONTAINED_DEPTH;
            break cycles via target-type set."""
            try:
                root_et = self._flat_entity_type_for(top_level_set, namespace)
            except ValueError:
                return []
            paths: list[str] = []
            root = self._metadata_root()
            type_to_qname: dict[ET.Element, str] = {
                et: f"{schema.get('Namespace') or ''}.{et.get('Name')}"
                for schema in root.iter(f"{_NS_EDM}Schema")
                for et in schema.findall(f"{_NS_EDM}EntityType")
            }
            queue: list[tuple[list[str], ET.Element, set[str]]] = [
                ([top_level_set], root_et, {type_to_qname.get(root_et, "")})
            ]
            while queue:
                segments, et, seen = queue.pop(0)
                if len(segments) >= MAX_CONTAINED_DEPTH:
                    continue
                for nav_name, target_ref in self._all_contained_nav_props(et):
                    if target_ref in seen:
                        continue
                    target_et = self._resolve_type_ref(target_ref)
                    if target_et is None:
                        continue
                    new_segments = segments + [nav_name]
                    paths.append(CONTAINED_PATH_SEP.join(new_segments))
                    queue.append((new_segments, target_et, seen | {target_ref}))
            return paths

        # --- option parsing ----------------------------------------------------

        def _expand_contained_active(self, table_options: dict[str, str] | None) -> bool:
            """Parse the boolean ``expand_contained`` table option."""
            raw = ((table_options or {}).get("expand_contained") or "false").strip().lower()
            if raw not in {"true", "false"}:
                raise ValueError(f"Invalid expand_contained={raw!r}. Expected one of: true, false.")
            return raw == "true"

        # --- URL construction --------------------------------------------------

        def _format_key_predicate(self, pk_values: dict[str, Any]) -> str:
            """``(value)`` for single key; ``(K1=v1,K2=v2)`` for composite."""
            if len(pk_values) == 1:
                return f"({odata_literal(next(iter(pk_values.values())))})"
            return "(" + ",".join(f"{k}={odata_literal(v)}" for k, v in pk_values.items()) + ")"

        def _build_contained_path(self, segments: list[str], key_chain: list[dict[str, Any]]) -> str:
            """``A(1)/B('x')/C`` — leaf segment has no key; ``key_chain`` len = N-1."""
            if len(key_chain) != len(segments) - 1:
                raise ValueError(
                    f"key_chain length {len(key_chain)} does not match "
                    f"non-leaf segment count {len(segments) - 1}"
                )
            return _URL_SEGMENT_SEP.join(
                f"{seg}{self._format_key_predicate(key_chain[i])}" if i < len(key_chain) else seg
                for i, seg in enumerate(segments)
            )

        def _build_contained_url(
            self,
            segments: list[str],
            key_chain: list[dict[str, Any]],
            table_options: dict[str, str],
            extra_filter: str | None = None,
            order_by: str | None = None,
        ) -> str:
            """Full URL for a contained-collection read at one parent tuple."""
            base = join_url(self.service_url, self._build_contained_path(segments, key_chain))
            return f"{base}?{self._format_query_params(table_options, extra_filter, order_by)}"

        def _build_expand_url(
            self,
            segments: list[str],
            table_options: dict[str, str],
            cursor_level: int | None = None,
            cursor_filter: str | None = None,
            cursor_order: str | None = None,
            cursor_select: str | None = None,
        ) -> str:
            """``A?...&$expand=B($expand=C($expand=D))`` for the full chain.

            When ``cursor_level`` is set, ``cursor_filter``/``cursor_order``/
            ``cursor_select`` are injected at the segment that owns the
            cursor — at the top-level URL when ``cursor_level == 0``, or
            inside the corresponding ``$expand`` clause otherwise. The
            ``$select`` is necessary because some OData servers omit
            properties from ``$expand`` responses by default; explicitly
            requesting the cursor guarantees the server projects it onto
            the ancestor rows so it can be stamped onto leaf rows. OData
            v4 §5.1.1.13: inner ``$expand`` options are separated by ``;``."""
            top, *children = segments
            base = join_url(self.service_url, top)
            if cursor_level == 0:
                query = self._format_query_params(table_options, cursor_filter, cursor_order)
            else:
                query = self._format_query_params(table_options, None, None)
            if not children:
                return f"{base}?{query}"
            inner = ""
            for i in range(len(children) - 1, -1, -1):
                parts: list[str] = []
                if cursor_level == i + 1:
                    if cursor_select:
                        parts.append(f"$select={cursor_select}")
                    if cursor_filter:
                        parts.append(f"$filter={cursor_filter}")
                    if cursor_order:
                        parts.append(f"$orderby={cursor_order}")
                if inner:
                    parts.append(f"$expand={inner}")
                inner = f"{children[i]}({';'.join(parts)})" if parts else children[i]
            return f"{base}?{query}&$expand={inner}"

        # --- read paths --------------------------------------------------------

        def _resolve_fk_columns(
            self, segments: list[str], namespace: str | None
        ) -> dict[tuple[str, str], str]:
            """Map ``(segment, pk_name) → unique FK column name`` for every
            non-leaf ancestor.

            OData v4 §13.4.3 makes contained-entity keys unique only within
            their immediate parent, so the destination composite key needs
            the full ancestor chain to be globally unique. Default name is
            ``<segment>_<pk>``; collisions get a leading ``_`` until unique.
            Empty mapping for flat tables.
            """
            if len(segments) < 2:
                return {}
            leaf_field_names = {
                f.name
                for f in self._own_fields_for_et(
                    self._entity_type_for(CONTAINED_PATH_SEP.join(segments), namespace)
                )
            }
            used = set(leaf_field_names)
            resolved: dict[tuple[str, str], str] = {}
            for idx in range(len(segments) - 1):
                ancestor_et = self._entity_type_for(
                    CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace
                )
                seg = segments[idx]
                for pk in self._own_primary_keys_for_et(ancestor_et):
                    candidate = fk_column_name(seg, pk)
                    while candidate in used:
                        candidate = "_" + candidate
                    resolved[(seg, pk)] = candidate
                    used.add(candidate)
            return resolved

        def _tag_with_ancestor_fks(
            self,
            row: dict,
            segments: list[str],
            chain: list[dict[str, Any]],
            fk_columns: dict[tuple[str, str], str],
        ) -> None:
            """Write every ancestor's primary-key values onto ``row`` under
            the resolved FK column names from ``fk_columns``."""
            for idx, ancestor_keys in enumerate(chain):
                seg = segments[idx]
                for pk_name, pk_val in ancestor_keys.items():
                    col = fk_columns.get((seg, pk_name))
                    if col is not None:
                        row[col] = pk_val

        def _find_cursor_level(
            self,
            segments: list[str],
            namespace: str | None,
            cursor_field: str,
        ) -> int:
            """Return the segment index whose entity type declares
            ``cursor_field`` as a property. Walk leaf → root; the closest
            match wins. Returns ``-1`` if no segment has it."""
            for idx in range(len(segments) - 1, -1, -1):
                et = self._entity_type_for(CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace)
                if any(f.name == cursor_field for f in self._own_fields_for_et(et)):
                    return idx
            return -1

        def _ancestor_cursor_field(
            self, table_name: str, namespace: str | None, cursor_field: str
        ) -> StructField | None:
            """``StructField`` for ``cursor_field`` when it lives on a non-leaf
            ancestor of a contained path; ``None`` when the leaf owns it or
            the path is flat. Used by ``get_table_schema`` to add the column
            to the leaf schema."""
            segments = parse_contained_path(table_name) or [table_name]
            if len(segments) < 2:
                return None
            cursor_level = self._find_cursor_level(segments, namespace, cursor_field)
            if cursor_level in (-1, len(segments) - 1):
                return None
            ancestor_et = self._entity_type_for(
                CONTAINED_PATH_SEP.join(segments[: cursor_level + 1]), namespace
            )
            for field in self._own_fields_for_et(ancestor_et):
                if field.name == cursor_field:
                    return field
            return None

        def _iter_parent_chains_with_cursor(
            self,
            segments: list[str],
            namespace: str | None,
            table_options: dict[str, str] | None,
            cursor_level: int,
            cursor_field: str,
            since: Any,
        ) -> Iterator[tuple[list[dict[str, Any]], Any]]:
            """Like ``_iter_parent_key_chains`` but applies a cursor filter at
            the ancestor that owns ``cursor_field``. Yields
            ``(chain, ancestor_cursor_value)`` pairs; the cursor value is the
            value at ``cursor_level`` for that chain."""

            def _walk(level: int, chain: list[dict[str, Any]], cur_val: Any):
                if level == len(segments) - 1:
                    yield list(chain), cur_val
                    return
                sub_segments = segments[: level + 1]
                ancestor_et = self._entity_type_for(CONTAINED_PATH_SEP.join(sub_segments), namespace)
                ancestor_pks = self._own_primary_keys_for_et(ancestor_et)
                if not ancestor_pks:
                    raise ValueError(
                        f"Cannot walk contained path: segment {segments[level]!r} "
                        f"has no primary key declared in $metadata."
                    )
                select_cols = list(ancestor_pks)
                extra_filter: str | None = None
                order_by: str | None = None
                if level == cursor_level:
                    if cursor_field not in select_cols:
                        select_cols.append(cursor_field)
                    extra_filter = self._cursor_filter(cursor_field, since)
                    terms = [f"{cursor_field} asc"]
                    terms.extend(f"{pk} asc" for pk in ancestor_pks if pk != cursor_field)
                    order_by = ",".join(terms)
                opts = {
                    "page_size": (table_options or {}).get("page_size", "1000"),
                    "select": ",".join(select_cols),
                }
                url = (
                    self._build_url(segments[0], opts, extra_filter=extra_filter, order_by=order_by)
                    if level == 0
                    else self._build_contained_url(
                        sub_segments,
                        chain,
                        opts,
                        extra_filter=extra_filter,
                        order_by=order_by,
                    )
                )
                for row in self._fetch_pages(url):
                    next_cur = row.get(cursor_field) if level == cursor_level else cur_val
                    chain.append({pk: row.get(pk) for pk in ancestor_pks})
                    yield from _walk(level + 1, chain, next_cur)
                    chain.pop()

            yield from _walk(0, [], None)

        def _iter_parent_key_chains(
            self,
            segments: list[str],
            namespace: str | None,
            table_options: dict[str, str] | None,
        ) -> Iterator[list[dict[str, Any]]]:
            """Yield every ancestor key chain (len = len(segments) - 1) reaching
            the leaf. Each level fetched with ``$select=<pks>``; user ``filter``
            not forwarded."""

            def _walk(level: int, chain: list[dict[str, Any]]):
                if level == len(segments) - 1:
                    yield list(chain)
                    return
                sub_segments = segments[: level + 1]
                ancestor_et = self._entity_type_for(CONTAINED_PATH_SEP.join(sub_segments), namespace)
                ancestor_pks = self._own_primary_keys_for_et(ancestor_et)
                if not ancestor_pks:
                    raise ValueError(
                        f"Cannot walk contained path: segment {segments[level]!r} "
                        f"has no primary key declared in $metadata."
                    )
                opts = {
                    "page_size": (table_options or {}).get("page_size", "1000"),
                    "select": ",".join(ancestor_pks),
                }
                url = (
                    self._build_url(segments[0], opts)
                    if level == 0
                    else self._build_contained_url(sub_segments, chain, opts)
                )
                for row in self._fetch_pages(url):
                    chain.append({pk: row.get(pk) for pk in ancestor_pks})
                    yield from _walk(level + 1, chain)
                    chain.pop()

            yield from _walk(0, [])

        def _read_contained_snapshot(
            self, table_name: str, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            """Walk the parent-key tree N+1 and emit leaf rows tagged with
            ancestor FKs. Full result in one call."""
            segments = parse_contained_path(table_name) or [table_name]
            namespace = (table_options or {}).get("namespace")
            fk_columns = self._resolve_fk_columns(segments, namespace)
            emitted: list[dict] = []
            for chain in self._iter_parent_key_chains(segments, namespace, table_options):
                for row in self._fetch_pages(self._build_contained_url(segments, chain, table_options)):
                    self._tag_with_ancestor_fks(row, segments, chain, fk_columns)
                    emitted.append(row)
            return iter(emitted), {}

        def _read_contained_expand(
            self,
            table_name: str,
            start_offset: dict,
            table_options: dict[str, str],
        ) -> tuple[Iterator[dict], dict]:
            """Single GET with nested ``$expand``; flatten the response into
            leaf rows tagged with ancestor FKs. When ``cursor_field`` is
            set, a ``$filter``/``$orderby`` is injected at the closest
            segment that owns the cursor (top-level query or inner
            ``$expand``), restricting the response to changed subtrees.
            Emitted leaf rows are stamped with the cursor value from that
            segment when they don't carry it themselves. Server depth caps
            surface as HTTP 4xx — no client-side fallback."""
            segments = parse_contained_path(table_name) or [table_name]
            if len(segments) < 2:
                raise ValueError(f"expand_contained requires a contained path; {table_name!r} is flat.")
            namespace = (table_options or {}).get("namespace")
            cursor_field = (table_options or {}).get("cursor_field")
            cursor_level, cursor_filter, cursor_order, cursor_select = self._cursor_expand_clause(
                segments, namespace, cursor_field, (start_offset or {}).get("cursor")
            )
            if cursor_field and cursor_level == -1:
                raise ValueError(
                    f"cursor_field={cursor_field!r} is not a property of any "
                    f"segment in {table_name!r}."
                )
            pks_per_level: list[list[str]] = []
            for idx in range(len(segments) - 1):
                et = self._entity_type_for(CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace)
                pks = self._own_primary_keys_for_et(et)
                if not pks:
                    raise ValueError(
                        f"Cannot $expand contained path: segment {segments[idx]!r} "
                        f"has no primary key declared in $metadata."
                    )
                pks_per_level.append(pks)
            fk_columns = self._resolve_fk_columns(segments, namespace)
            url = self._build_expand_url(
                segments,
                table_options,
                cursor_level=cursor_level if cursor_field else None,
                cursor_filter=cursor_filter,
                cursor_order=cursor_order,
                cursor_select=cursor_select,
            )
            emitted: list[dict] = []
            ctx = (cursor_field, cursor_level, None) if cursor_field else None
            for top_row in self._fetch_pages(url):
                self._flatten_expand_response(
                    0, top_row, segments, pks_per_level, [], fk_columns, emitted, ctx
                )
            if not cursor_field:
                return iter(emitted), {}
            if not emitted:
                return iter([]), start_offset or {}
            cursors = [r.get(cursor_field) for r in emitted if r.get(cursor_field) is not None]
            end_offset: dict = {"cursor": max(cursors)} if cursors else dict(start_offset or {})
            if start_offset and start_offset == end_offset:
                return iter([]), start_offset
            return iter(emitted), end_offset

        def _cursor_expand_clause(
            self,
            segments: list[str],
            namespace: str | None,
            cursor_field: str | None,
            since: Any,
        ) -> tuple[int, str | None, str | None, str | None]:
            """``(cursor_level, $filter, $orderby, $select)`` for ``$expand``
            mode. Returns ``(-1, None, None, None)`` when no cursor is set;
            the caller raises if the cursor isn't a property of any segment.
            ``$select`` is non-empty only when the cursor lives on a non-top
            segment — it forces the server to project the cursor column on
            the expanded ancestor (some servers default-omit it)."""
            if not cursor_field:
                return -1, None, None, None
            cursor_level = self._find_cursor_level(segments, namespace, cursor_field)
            if cursor_level == -1:
                return -1, None, None, None
            level_et = self._entity_type_for(
                CONTAINED_PATH_SEP.join(segments[: cursor_level + 1]), namespace
            )
            level_pks = self._own_primary_keys_for_et(level_et)
            order_terms = [f"{cursor_field} asc"]
            order_terms.extend(f"{p} asc" for p in level_pks if p != cursor_field)
            # No ``$select`` injection: the cursor column is returned by
            # default projection on declared CSDL properties, so it isn't
            # needed for stamping. Adding it silently trims other columns
            # the user didn't opt out of — particularly harmful when the
            # cursor segment is also the leaf (2-segment paths). Users who
            # want to trim can set ``select`` themselves on the leaf side.
            return (
                cursor_level,
                self._cursor_filter(cursor_field, since),
                ",".join(order_terms),
                None,
            )

        def _flatten_expand_response(
            self,
            level: int,
            row: dict,
            segments: list[str],
            pks_per_level: list[list[str]],
            chain: list[dict[str, Any]],
            fk_columns: dict[tuple[str, str], str],
            out: list[dict],
            cursor_ctx: tuple[str | None, int, Any] | None = None,
        ) -> None:
            """Recurse into the nested $expand payload; tag and emit leaf rows.
            ``cursor_ctx`` is ``(cursor_field, cursor_level, captured_value)``
            threaded down the recursion: when ``level == cursor_level`` the
            captured value snaps to ``row[cursor_field]`` and propagates to
            every leaf row beneath, stamped only when the leaf doesn't
            already carry the column."""
            cur_field, cur_level, cur_val = cursor_ctx or (None, -1, None)
            if cur_field and level == cur_level:
                cur_val = row.get(cur_field)
            if level == len(segments) - 1:
                clean = {k: v for k, v in row.items() if not k.startswith("@odata.")}
                self._tag_with_ancestor_fks(clean, segments, chain, fk_columns)
                if cur_field and cur_val is not None and clean.get(cur_field) is None:
                    clean[cur_field] = cur_val
                out.append(clean)
                return
            pks = pks_per_level[level]
            chain.append({pk: row.get(pk) for pk in pks})
            next_ctx = (cur_field, cur_level, cur_val) if cur_field else None
            for child in row.get(segments[level + 1]) or []:
                self._flatten_expand_response(
                    level + 1, child, segments, pks_per_level, chain, fk_columns, out, next_ctx
                )
            chain.pop()

        def _leaf_cursor_order_by(
            self, table_name: str, namespace: str | None, cursor_field: str
        ) -> str:
            """``cursor asc, pk1 asc, ...`` — unique total order so server
            skiptokens don't split same-cursor cohorts."""
            leaf_pks = self._own_primary_keys_for_et(self._entity_type_for(table_name, namespace))
            terms = [f"{cursor_field} asc"]
            terms.extend(f"{pk} asc" for pk in leaf_pks if pk != cursor_field)
            return ",".join(terms)

        def _walk_contained_with_cursor(
            self,
            segments: list[str],
            chains: list[list[dict[str, Any]]],
            parent_idx_start: int,
            table_options: dict[str, str],
            order_by: str,
            cursor_field: str,
            since: Any,
            truncated_chain_cursor: Any,
            chain_next_link: str | None,
            max_records: int,
            fk_columns: dict[tuple[str, str], str],
        ) -> tuple[list[dict], bool, int, int, str | None]:
            """Drive the per-parent fetch loop (leaf-cursor mode).

            Resume preference, applied to ``chains[parent_idx_start]`` only:

            1. ``chain_next_link`` (server skiptoken) — fetched directly,
               bypassing URL rebuild. Used when the previous batch parked
               at a page boundary mid-chain.
            2. ``truncated_chain_cursor`` — used as ``cursor gt <value>``
               in a freshly-built URL. Used when the previous batch had
               to apply the Option A boundary trim at mid-page truncation
               (server skiptoken couldn't represent the row-level position).
            3. Otherwise the global ``since`` is used.

            Pagination is page-aware: rows are emitted as each page arrives,
            and a truncation that lands at a page boundary checkpoints with
            the response's @odata.nextLink. Mid-page truncations leave
            ``chain_next_link_out`` as ``None`` so the caller falls back to
            the Option A trim path.

            Returns ``(rows, truncated, parent_idx, truncated_chain_start_idx,
            chain_next_link_out)``."""
            emitted: list[dict] = []
            truncated = False
            parent_idx = parent_idx_start
            chain_start_idx = 0
            chain_next_link_out: str | None = None
            while parent_idx < len(chains):
                chain = chains[parent_idx]
                chain_start_idx = len(emitted)
                chain_since: Any
                initial_url: str
                if parent_idx == parent_idx_start and chain_next_link is not None:
                    # Resume from the server's own skiptoken; no client-side
                    # filter — the link already encodes filter/order state.
                    chain_since = None
                    initial_url = chain_next_link
                else:
                    if parent_idx == parent_idx_start and truncated_chain_cursor is not None:
                        chain_since = truncated_chain_cursor
                    else:
                        chain_since = since
                    initial_url = self._build_contained_url(
                        segments,
                        chain,
                        table_options,
                        extra_filter=self._cursor_filter(cursor_field, chain_since),
                        order_by=order_by,
                    )
                cap_hit_in_page = False
                page_next_url: str | None = None
                for page_rows, page_next_url in self._fetch_pages_with_links(initial_url):
                    for row in page_rows:
                        rec_cursor = row.get(cursor_field)
                        if (
                            chain_since is not None
                            and rec_cursor is not None
                            and rec_cursor <= chain_since
                        ):
                            continue
                        self._tag_with_ancestor_fks(row, segments, chain, fk_columns)
                        emitted.append(row)
                        if len(emitted) >= max_records:
                            cap_hit_in_page = True
                    if cap_hit_in_page:
                        # Finish the current page so the server's nextLink
                        # (page-after-this-one) is a clean checkpoint, but
                        # don't fetch any more pages for this chain.
                        truncated = True
                        # ``page_next_url`` is None ⇒ chain ended on this page;
                        # caller falls back to Option A trim. Non-None ⇒
                        # caller parks chain_next_link.
                        chain_next_link_out = page_next_url
                        break
                if truncated:
                    break
                parent_idx += 1
            return emitted, truncated, parent_idx, chain_start_idx, chain_next_link_out

        def _read_contained_incremental(
            self,
            table_name: str,
            start_offset: dict,
            table_options: dict[str, str],
            cursor_field: str,
        ) -> tuple[Iterator[dict], dict]:
            """Walk every parent tuple with ``$filter=cursor gt since``; track
            global max cursor in the offset. Truncation parks ``parent_idx``
            for next-call resume. When the leaf entity doesn't declare
            ``cursor_field``, the closest ancestor that does owns the filter
            and its cursor value is propagated onto each leaf row."""
            segments = parse_contained_path(table_name) or [table_name]
            namespace = (table_options or {}).get("namespace")
            cursor_level = self._find_cursor_level(segments, namespace, cursor_field)
            if cursor_level == -1:
                raise ValueError(
                    f"cursor_field {cursor_field!r} is not a property on "
                    f"{table_name!r} or any of its ancestors. Pick a column "
                    f"declared on the leaf or one of the parent segments."
                )
            if cursor_level == len(segments) - 1:
                return self._read_contained_incremental_leaf_cursor(
                    segments, start_offset, table_options, cursor_field
                )
            return self._read_contained_incremental_ancestor_cursor(
                segments, start_offset, table_options, cursor_field, cursor_level
            )

        def _read_contained_incremental_leaf_cursor(
            self,
            segments: list[str],
            start_offset: dict,
            table_options: dict[str, str],
            cursor_field: str,
        ) -> tuple[Iterator[dict], dict]:
            """Cursor lives on the leaf entity — filter at the leaf fetch.

            Truncation has two recovery shapes, applied to the truncated
            chain only (subsequent chains keep using the original
            ``since``, since per-chain cursor distributions are
            independent):

            * **NextLink (preferred)**: when truncation lands on a page
              boundary, the server's @odata.nextLink is parked in the
              offset as ``chain_next_link`` and the resumed call hands it
              straight back to the server. No client-side filter
              reconstruction; no boundary-cohort math.
            * **Option A trim (fallback)**: when truncation lands
              mid-page (the skiptoken can't represent a row-level
              position), the trailing same-cursor cohort within the
              truncated chain's emit is dropped and the chain's last
              distinct cursor is parked as ``truncated_chain_cursor``.
              The resumed call rebuilds the URL with
              ``cursor gt truncated_chain_cursor`` for that chain only.
              If trimming leaves the chain with zero rows, the cohort
              exceeded ``max_records_per_batch`` on its own and the
              connector raises ``RuntimeError`` — same shape as the
              flat-path failure mode.
            """
            namespace = (table_options or {}).get("namespace")
            table_name = CONTAINED_PATH_SEP.join(segments)
            since = (start_offset or {}).get("cursor")
            truncated_chain_cursor_in = (start_offset or {}).get("truncated_chain_cursor")
            chain_next_link_in = (start_offset or {}).get("chain_next_link")
            max_records = int((table_options or {}).get("max_records_per_batch", "100000"))
            order_by = self._leaf_cursor_order_by(table_name, namespace, cursor_field)
            chains = list(self._iter_parent_key_chains(segments, namespace, table_options))
            (
                emitted,
                truncated,
                parent_idx,
                chain_start_idx,
                chain_next_link_out,
            ) = self._walk_contained_with_cursor(
                segments,
                chains,
                int((start_offset or {}).get("parent_idx", 0)),
                table_options,
                order_by,
                cursor_field,
                since,
                truncated_chain_cursor_in,
                chain_next_link_in,
                max_records,
                self._resolve_fk_columns(segments, namespace),
            )
            if truncated:
                if chain_next_link_out is not None:
                    end_offset: dict = {
                        "parent_idx": parent_idx,
                        "chain_next_link": chain_next_link_out,
                    }
                    if since is not None:
                        end_offset["cursor"] = since
                else:
                    trimmed_chain = _trim_to_distinct_cursor_boundary(
                        emitted[chain_start_idx:], cursor_field
                    )
                    if not trimmed_chain:
                        raise RuntimeError(
                            f"max_records_per_batch={max_records} is smaller than "
                            f"the largest same-cursor cohort under one parent in "
                            f"contained path {table_name!r}. Raise "
                            f"max_records_per_batch above that cohort, or pick a "
                            f"higher-cardinality cursor."
                        )
                    emitted = emitted[:chain_start_idx] + trimmed_chain
                    end_offset = {
                        "parent_idx": parent_idx,
                        "truncated_chain_cursor": trimmed_chain[-1].get(cursor_field),
                    }
                    if since is not None:
                        end_offset["cursor"] = since
            else:
                if not emitted:
                    return iter([]), start_offset or {}
                cursors = [r.get(cursor_field) for r in emitted if r.get(cursor_field) is not None]
                end_offset = {"cursor": max(cursors) if cursors else since}
            if start_offset and start_offset == end_offset:
                return iter([]), start_offset
            return iter(emitted), end_offset

        def _read_contained_incremental_ancestor_cursor(
            self,
            segments: list[str],
            start_offset: dict,
            table_options: dict[str, str],
            cursor_field: str,
            cursor_level: int,
        ) -> tuple[Iterator[dict], dict]:
            """Cursor lives on a non-leaf ancestor. Filter at that ancestor
            level (changed subtrees only), fetch full leaf collections under
            each filtered ancestor, and stamp the ancestor's cursor value
            onto every emitted leaf row.

            Truncation uses **nextLink-based mid-chain resume** exclusively.
            Every leaf under a chain shares that chain's stamped cursor by
            construction, so a within-chain ``cursor gt`` rebuild would
            either re-fetch the whole chain or skip the whole chain — there
            is no meaningful split. The server's @odata.nextLink, on the
            other hand, encodes the chain's pagination position
            independently of cursor values, so the resumed call hands it
            back and the server picks up exactly where it stopped.

            On a truncation:

            * If we stopped at a page boundary mid-chain (next page exists),
              park ``chain_next_link`` in the offset.
            * If we stopped because the chain happened to end on the
              truncating page, just advance ``parent_idx`` past it.
            """
            namespace = (table_options or {}).get("namespace")
            since = (start_offset or {}).get("cursor")
            chain_next_link_in = (start_offset or {}).get("chain_next_link")
            max_records = int((table_options or {}).get("max_records_per_batch", "100000"))
            fk_columns = self._resolve_fk_columns(segments, namespace)
            chains_with_cursor = list(
                self._iter_parent_chains_with_cursor(
                    segments,
                    namespace,
                    table_options,
                    cursor_level,
                    cursor_field,
                    since,
                )
            )
            parent_idx_start = int((start_offset or {}).get("parent_idx", 0))
            parent_idx = parent_idx_start
            emitted: list[dict] = []
            truncated = False
            chain_next_link_out: str | None = None
            while parent_idx < len(chains_with_cursor):
                chain, ancestor_cursor = chains_with_cursor[parent_idx]
                if parent_idx == parent_idx_start and chain_next_link_in is not None:
                    initial_url = chain_next_link_in
                else:
                    initial_url = self._build_contained_url(segments, chain, table_options)
                page_next_url: str | None = None
                for page_rows, page_next_url in self._fetch_pages_with_links(initial_url):
                    for row in page_rows:
                        self._tag_with_ancestor_fks(row, segments, chain, fk_columns)
                        row[cursor_field] = ancestor_cursor
                        emitted.append(row)
                    if len(emitted) >= max_records:
                        truncated = True
                        break
                if truncated:
                    # Page-boundary checkpoint: mid-chain only if the chain has
                    # more pages left. Otherwise the chain finished on the
                    # truncating page and we can simply advance parent_idx.
                    if page_next_url is not None:
                        chain_next_link_out = page_next_url
                    else:
                        parent_idx += 1
                        chain_next_link_out = None
                    break
                parent_idx += 1
            # Offset semantics:
            #
            # * On truncation, preserve the **original** ``since`` (start
            #   offset's cursor) so the resumed call's chain rebuild covers
            #   the same set as the prior batch. Ancestor cursors interleave
            #   across top-level parents (depth-first walk), so advancing
            #   ``since`` to the global max would silently skip lower-cursor
            #   chains under not-yet-walked parents.
            # * Carry ``running_max`` across resume batches: every batch
            #   max-merges its own emitted cursors with what's already in
            #   ``running_max``. On natural completion that accumulated
            #   value becomes the next regular trigger's ``cursor`` floor —
            #   without it, completing a resume that originated from
            #   ``since=None`` would drop the cursor entirely and re-walk
            #   the whole table on the next trigger.
            # * Cross-batch re-emission of already-seen chains during the
            #   resume cycle is deduped by ``apply_changes`` on the
            #   composite PK; correctness over minimal bandwidth.
            end_offset: dict
            cursors = [r.get(cursor_field) for r in emitted if r.get(cursor_field) is not None]
            this_batch_max = max(cursors) if cursors else None
            prev_running_max = (start_offset or {}).get("running_max")
            if this_batch_max is not None and prev_running_max is not None:
                new_running_max: Any = max(this_batch_max, prev_running_max)
            elif this_batch_max is not None:
                new_running_max = this_batch_max
            else:
                new_running_max = prev_running_max
            if truncated:
                end_offset = {"parent_idx": parent_idx}
                if since is not None:
                    end_offset["cursor"] = since
                if chain_next_link_out is not None:
                    end_offset["chain_next_link"] = chain_next_link_out
                if new_running_max is not None:
                    end_offset["running_max"] = new_running_max
            else:
                if new_running_max is not None:
                    end_offset = {"cursor": new_running_max}
                elif since is not None:
                    end_offset = {"cursor": since}
                else:
                    end_offset = {}
            if start_offset and start_offset == end_offset:
                return iter([]), start_offset
            return iter(emitted), end_offset


    ########################################################
    # src/databricks/labs/community_connector/sources/odata/odata.py
    ########################################################

    _EDM_TO_SPARK = {
        "Edm.String": StringType(),
        "Edm.Boolean": BooleanType(),
        # Widen integers up to Int32 to IntegerType (the framework's
        # parse_value doesn't support ShortType or ByteType, so the narrow
        # EDM widths can't map to their natural Spark types). Int64 needs
        # the full 64-bit range, so it stays as LongType.
        "Edm.Byte": IntegerType(),
        "Edm.SByte": IntegerType(),
        "Edm.Int16": IntegerType(),
        "Edm.Int32": IntegerType(),
        "Edm.Int64": LongType(),
        "Edm.Single": FloatType(),
        "Edm.Double": DoubleType(),
        "Edm.Decimal": DecimalType(38, 18),
        "Edm.Date": DateType(),
        "Edm.DateTime": TimestampType(),
        "Edm.DateTimeOffset": TimestampType(),
        "Edm.TimeOfDay": StringType(),
        "Edm.Duration": StringType(),
        "Edm.Guid": StringType(),
        "Edm.Binary": BinaryType(),
    }

    _NS_EDMX = "{http://docs.oasis-open.org/odata/ns/edmx}"
    _NS_EDM = "{http://docs.oasis-open.org/odata/ns/edm}"

    # Delta tracking constants.
    #
    # Synthetic columns appended to the schema when delta is active so the
    # destination MERGE (apply_changes) has a sequence column and a tombstone
    # flag. Their names are namespaced so they can't collide with any real
    # OData property — OData property names start with a letter, never an
    # underscore.
    _DELTA_PREFER = "odata.track-changes"
    _DELETED_COL = "_deleted"
    _SEQUENCE_COL = "_lc_sequence"
    # Monotonic across the whole process — guarantees each emitted record
    # has a strictly increasing sequence value, so apply_changes can pick a
    # deterministic winner when the same primary key appears multiple times
    # in one batch (e.g. update then delete arriving back-to-back).
    _SEQUENCE_COUNTER = itertools.count()


    def _next_sequence() -> str:
        """Strictly-increasing per-record sequence value for apply_changes.

        ISO-8601 prefix keeps the value human-readable and sortable
        lexicographically across pipeline restarts; the integer suffix
        distinguishes records emitted in the same microsecond.
        """
        now = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%S.%fZ")
        return f"{now}_{next(_SEQUENCE_COUNTER):012d}"


    class ODataLakeflowConnect(LakeflowConnect, SupportsNamespaces, ContainedNavMixin):
        """LakeflowConnect implementation for OData v4 services.

        OData ``$metadata`` documents can declare multiple ``<Schema>`` blocks,
        each with its own namespace and its own entity sets. Two schemas in the
        same service can re-use entity set names (e.g. ``Sales.Customers`` and
        ``HR.Customers``), so this connector exposes the schema namespace as a
        single-segment Lakeflow namespace path.

        Pipelines disambiguate by passing ``namespace`` in *table_options*. When
        only one schema declares a given table name, ``namespace`` may be omitted.
        """

        def __init__(self, options: dict[str, str]) -> None:
            super().__init__(options)
            self.service_url = _require(options, "service_url")
            self.timeout = int(options.get("timeout_seconds", "60"))
            self._session: requests.Session | None = None
            self._metadata_xml: str | None = None
            # Monotonic deadline (seconds) for the current OAuth access token.
            # Set when the token endpoint returns ``expires_in``; `None` means we
            # don't know the expiry (user-supplied access token without metadata)
            # so we fall through to the 401-retry path only.
            self._access_token_expires_at: float | None = None
            # Delta-tracking capability cache, keyed by (namespace_or_empty,
            # table_name). Populated lazily by ``_probe_delta_support`` on the
            # first metadata-resolution call for each table in ``auto`` mode.
            # ``enabled`` mode trusts the user and skips the cache; ``disabled``
            # mode never touches it.
            self._delta_capable: dict[tuple[str, str], bool] = {}

        # ------------------------------------------------------------------
        # LakeflowConnect interface
        # ------------------------------------------------------------------

        def list_tables(self) -> list[str]:
            """Flat fallback used by the framework when SupportsNamespaces is absent.

            Includes both top-level entity sets and contained collections
            reachable via ``ContainsTarget="true"`` navigation properties
            (double-underscore-pathed, e.g. ``Instances__Assets__AssetDocuments``).
            """
            names: set[str] = set()
            for ns, es_name in self._entity_set_index():
                names.add(es_name)
                names.update(self._enumerate_contained_paths(es_name, ns))
            return sorted(names)

        def list_namespaces(self, prefix: list[str] | None = None) -> list[list[str]]:
            # OData has a single, flat level of schema namespaces. Anything
            # below the root has no further children.
            if prefix:
                return []
            index = self._entity_set_index()
            seen = sorted({ns for ns, _ in index if ns})
            return [[ns] for ns in seen]

        def list_tables_in_namespace(self, namespace: list[str]) -> list[str]:
            index = self._entity_set_index()
            if not namespace:
                # Entity sets always live inside a Schema with a Namespace
                # attribute; root-level tables don't exist in OData v4.
                return []
            target = namespace[0]
            flat = sorted({es for ns, es in index if ns == target})
            contained: set[str] = set()
            for es_name in flat:
                contained.update(self._enumerate_contained_paths(es_name, target))
            return flat + sorted(contained)

        def get_table_schema(self, table_name: str, table_options: dict[str, str]) -> StructType:
            namespace = (table_options or {}).get("namespace")
            fields = self._fields_for(table_name, namespace)
            select = (table_options or {}).get("select")
            if select:
                wanted = {c.strip() for c in select.split(",")}
                # ``select`` filters leaf columns only; FK columns survive.
                segments = _parse_contained_path(table_name) or [table_name]
                fk_names = set(self._resolve_fk_columns(segments, namespace).values())
                fields = [f for f in fields if f.name in fk_names or f.name in wanted]
            # Contained path + cursor_field lives on an ancestor → propagate
            # the ancestor's cursor column type onto the leaf schema. The
            # incremental read path stamps the value onto each emitted row.
            cursor_field = (table_options or {}).get("cursor_field")
            if cursor_field:
                ancestor_cursor = self._ancestor_cursor_field(table_name, namespace, cursor_field)
                if ancestor_cursor is not None and ancestor_cursor.name not in {f.name for f in fields}:
                    fields = list(fields) + [ancestor_cursor]
            if not fields:
                raise ValueError(
                    f"Could not derive a non-empty schema for entity set {table_name!r}. "
                    f"Check the 'select' option."
                )
            # When delta tracking is active for this table the connector emits
            # two synthetic columns alongside the entity's own properties:
            # ``_deleted`` (in-band tombstone flag) and ``_lc_sequence`` (the
            # cursor column apply_changes uses to order updates). Both must be
            # in the declared schema so Spark accepts the records.
            if self._delta_active_for(table_name, table_options):
                fields = list(fields) + [
                    StructField(_DELETED_COL, BooleanType(), False),
                    StructField(_SEQUENCE_COL, StringType(), False),
                ]
            return StructType(fields)

        def read_table_metadata(self, table_name: str, table_options: dict[str, str]) -> dict:
            namespace = (table_options or {}).get("namespace")
            primary_keys = self._primary_keys_for(table_name, namespace)
            user_cursor = (table_options or {}).get("cursor_field")
            # Contained paths skip the delta probe (server delta is for
            # top-level sets only; mutex enforced in dispatch below).
            if _parse_contained_path(table_name) is None and self._delta_active_for(
                table_name, table_options
            ):
                return {
                    "primary_keys": primary_keys,
                    "cursor_field": _SEQUENCE_COL,
                    "ingestion_type": "cdc",
                }
            return {
                "primary_keys": primary_keys,
                "cursor_field": user_cursor,
                "ingestion_type": "cdc" if user_cursor else "snapshot",
            }

        def read_table(
            self, table_name: str, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            opts = table_options or {}
            offset = start_offset or {}
            if _parse_contained_path(table_name) is not None:
                if self._delta_setting(opts) == "enabled":
                    raise ValueError(
                        "delta_tracking=enabled is not supported on contained-"
                        "collection paths (server change tracking only applies "
                        "to top-level entity sets). Set delta_tracking=disabled "
                        "or ingest the parent set directly."
                    )
                if self._expand_contained_active(opts):
                    return self._read_contained_expand(table_name, offset, opts)
                if opts.get("cursor_field"):
                    return self._read_contained_incremental(
                        table_name, offset, opts, opts["cursor_field"]
                    )
                return self._read_contained_snapshot(table_name, opts)
            # Offset-shape check ahead of the delta predicate so a resumed
            # delta stream (offset carries delta_link / next_link) takes the
            # delta path even if delta_tracking is no longer set in options.
            if (
                "delta_link" in offset
                or "next_link" in offset
                or self._delta_active_for(table_name, opts)
            ):
                return self._read_incremental_delta(table_name, offset, opts)
            if opts.get("cursor_field"):
                return self._read_incremental(table_name, offset, opts, opts["cursor_field"])
            return self._read_snapshot(table_name, opts)

        # ------------------------------------------------------------------
        # Snapshot + incremental read paths
        # ------------------------------------------------------------------

        def _read_snapshot(
            self, table_name: str, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            url = self._build_url(table_name, table_options)
            records = list(self._fetch_pages(url))
            return iter(records), {}

        def _read_incremental(
            self,
            table_name: str,
            start_offset: dict,
            table_options: dict[str, str],
            cursor_field: str,
        ) -> tuple[Iterator[dict], dict]:
            # No wall-clock upper bound on the cursor — `max_records_per_batch`
            # is the only per-call cap. Each call fetches `cursor gt since`
            # (no `le` clause), advances the offset, and Spark drives the
            # call loop. Two consequences worth knowing:
            #   * Continuous SDP pipelines pick up new rows as they arrive,
            #     because we never freeze a "snapshot at startup" timestamp.
            #     The connector instance can live for the whole stream and
            #     each batch still sees fresh source state.
            #   * Cursor type doesn't matter for the filter. Timestamps,
            #     monotonic integer IDs, GUIDs — anything the server can
            #     order in `$orderby` and compare in `$filter` works the
            #     same way. There is no type mismatch between the cursor
            #     literal and the server's column type because we don't
            #     manufacture a timestamp ceiling out of wall-clock time.
            since = start_offset.get("cursor") if start_offset else None
            extra_filter = self._cursor_filter(cursor_field, since)
            # Append primary-key columns as $orderby tie-breakers. Without a
            # fully unique sort, OData servers that paginate internally (via
            # `@odata.nextLink` with a value-based skiptoken) can split a
            # same-cursor cohort across pages: the skiptoken's strict-`>` on
            # the cursor value drops the unread tail. A unique total ordering
            # forces the skiptoken to use the key as well, so no rows are lost.
            namespace = (table_options or {}).get("namespace")
            order_terms = [f"{cursor_field} asc"]
            for pk in self._primary_keys_for(table_name, namespace):
                if pk != cursor_field:
                    order_terms.append(f"{pk} asc")
            url = self._build_url(
                table_name,
                table_options,
                extra_filter=extra_filter,
                order_by=",".join(order_terms),
            )
            max_records = int(table_options.get("max_records_per_batch", "100000"))

            records: list[dict] = []
            truncated = False
            for row in self._fetch_pages(url):
                rec_cursor = row.get(cursor_field)
                if since is not None and rec_cursor is not None and rec_cursor <= since:
                    continue
                records.append(row)
                if len(records) >= max_records:
                    truncated = True
                    break

            if not records:
                return iter([]), start_offset or {}

            # Cursor boundary safety: the next call resumes with
            # `cursor gt <last_cursor>`, so if the trailing records share that
            # cursor with unseen records on the next page — OR with concurrently
            # inserted siblings that arrive before the next call — the `gt`
            # filter would silently drop them. Trim back to the last distinct
            # cursor on every batch (not just truncated ones), so a stop/restart
            # or natural completion can't lose same-cursor inserts at the boundary.
            # Re-fetched rows on the next call are deduped at the destination
            # via apply_changes' MERGE on the primary key.
            trimmed = _trim_to_distinct_cursor_boundary(records, cursor_field)
            if not trimmed:
                # Every record in this batch shares one cursor value.
                if truncated:
                    raise RuntimeError(
                        f"max_records_per_batch ({max_records}) is too small for "
                        f"{table_name!r}: every record in the batch shares cursor "
                        f"value {records[-1].get(cursor_field)!r}. Increase "
                        f"max_records_per_batch above the largest same-cursor "
                        f"cohort, or choose a higher-cardinality cursor field."
                    )
                # Natural exhaustion of a single-cursor cohort. Emit as-is —
                # trimming would lose data with no way to re-fetch. There's a
                # residual race for same-cursor rows added between now and any
                # future call, which is unavoidable without finer cursor resolution.
            else:
                records = trimmed

            # OData responses ordered by the cursor — last record carries the max.
            last_cursor = records[-1].get(cursor_field)
            end_offset = {"cursor": last_cursor}
            if start_offset and start_offset == end_offset:
                return iter([]), start_offset
            return iter(records), end_offset

        def _read_incremental_delta(
            self,
            table_name: str,
            start_offset: dict,
            table_options: dict[str, str],
        ) -> tuple[Iterator[dict], dict]:
            """Delta-tracked read via OData ``Prefer: odata.track-changes``.

            Three offset shapes, three entry behaviours:

            * No ``delta_link`` and no ``next_link`` — bootstrap. Send the
              initial entity-set GET with ``Prefer: odata.track-changes``,
              verify the server acknowledges via ``Preference-Applied``, and
              stream the full snapshot. The terminal page carries
              ``@odata.deltaLink``.
            * ``next_link`` set — we hit ``max_records_per_batch`` mid-
              pagination on a previous call. Resume by walking from that
              link.
            * ``delta_link`` set — server's "changes since" cursor. Walk
              ``@odata.nextLink`` chain (if any) until the terminal page
              delivers a fresh ``@odata.deltaLink``.

            Records emitted carry two synthetic columns: ``_deleted`` (bool,
            in-band tombstone flag — set ``True`` for ``@removed`` entries)
            and ``_lc_sequence`` (monotonic per-record string used as
            apply_changes' sequence column). The microsoft_teams connector
            established this convention in this repo; we follow it so the
            framework's standard ``cdc`` path handles tombstones without
            needing ``cdc_with_deletes`` + ``read_table_deletes`` split.
            """
            prev_delta_link = (start_offset or {}).get("delta_link")
            prev_next_link = (start_offset or {}).get("next_link")
            is_bootstrap = prev_delta_link is None and prev_next_link is None
            url, initial_headers = self._delta_initial_request(
                table_name, table_options, prev_delta_link, prev_next_link
            )

            namespace = (table_options or {}).get("namespace")
            primary_keys = self._primary_keys_for(table_name, namespace)
            max_records = int((table_options or {}).get("max_records_per_batch", "100000"))

            records, new_delta_link, carry_next_link, rebootstrap = self._delta_walk_pages(
                url=url,
                initial_headers=initial_headers,
                is_bootstrap=is_bootstrap,
                prev_delta_link=prev_delta_link,
                prev_next_link=prev_next_link,
                table_name=table_name,
                table_options=table_options,
                primary_keys=primary_keys,
                max_records=max_records,
            )
            if rebootstrap:
                # 410 Gone surfaced during pagination → re-bootstrap from
                # scratch. ``MERGE``-on-PK + ``_lc_sequence`` ordering
                # reconciles re-fetched rows at the destination; no data
                # loss, only HTTP cost.
                return self._read_incremental_delta(table_name, {}, table_options)

            # Graph-rotation guard. Some servers (notably Microsoft Graph)
            # mint a fresh ``@odata.deltaLink`` on every response, even when
            # the change set is empty. If we already had a delta link and
            # produced no records this call, hand back the prior link so the
            # framework sees ``end_offset == start_offset`` and a trigger
            # like AvailableNow can terminate. Following microsoft_teams.py.
            if prev_delta_link is not None and not records and not carry_next_link:
                return iter([]), {"delta_link": prev_delta_link}

            if carry_next_link:
                offset: dict = {"next_link": carry_next_link}
                # Preserve the prior delta_link as a fallback if the
                # next_link expires before the cap-resume call lands.
                if prev_delta_link is not None:
                    offset["delta_link"] = prev_delta_link
                return iter(records), offset

            if new_delta_link is None:
                # Reached end of stream without a deltaLink. Server is
                # misbehaving (spec requires the terminal page to carry one).
                # Resume from the prior delta_link if we have one — better
                # than losing the offset entirely.
                if prev_delta_link is not None:
                    return iter(records), {"delta_link": prev_delta_link}
                raise RuntimeError(
                    f"OData delta bootstrap for {table_name!r} ended without an "
                    f"@odata.deltaLink. The server may have aborted change "
                    f"tracking. Set delta_tracking=disabled to fall back to "
                    f"snapshot or cursor-based reads."
                )

            return iter(records), {"delta_link": new_delta_link}

        def _build_delta_record(self, item: dict, primary_keys: list[str]) -> dict:
            """Translate one delta payload entry into the emitted record shape.

            - ``@removed`` entries become tombstones: a record carrying the
              primary-key fields plus ``_deleted=True``.
            - Regular adds/changes pass through with all ``@odata.*`` control
              properties stripped and ``_deleted=False``.

            Every emitted record gets ``_lc_sequence`` — a strictly monotonic
            string — so apply_changes has a deterministic sequence_by column.
            """
            if "@removed" in item:
                record: dict = {pk: item.get(pk) for pk in primary_keys}
                record[_DELETED_COL] = True
            else:
                record = {k: v for k, v in item.items() if not k.startswith("@odata.")}
                record[_DELETED_COL] = False
            record[_SEQUENCE_COL] = _next_sequence()
            return record

        def _delta_initial_request(
            self,
            table_name: str,
            table_options: dict[str, str] | None,
            prev_delta_link: str | None,
            prev_next_link: str | None,
        ) -> tuple[str, dict[str, str] | None]:
            """Pick the first URL + headers for a delta read.

            ``next_link`` wins over ``delta_link`` when both are present —
            we were mid-pagination on a cap hit, finish that before
            consulting the prior change cursor.
            """
            if prev_next_link is not None:
                return prev_next_link, None
            if prev_delta_link is not None:
                return prev_delta_link, None
            return self._build_url(table_name, table_options or {}), {"Prefer": _DELTA_PREFER}

        def _delta_walk_pages(
            self,
            *,
            url: str,
            initial_headers: dict[str, str] | None,
            is_bootstrap: bool,
            prev_delta_link: str | None,
            prev_next_link: str | None,
            table_name: str,
            table_options: dict[str, str] | None,
            primary_keys: list[str],
            max_records: int,
        ) -> tuple[list[dict], str | None, str | None, bool]:
            """Walk the ``@odata.nextLink`` chain until a deltaLink, cap, or 410.

            Returns ``(records, new_delta_link, carry_next_link, rebootstrap)``:

            * ``records`` — emitted records (already passed through
              :py:meth:`_build_delta_record`).
            * ``new_delta_link`` — the freshest ``@odata.deltaLink`` seen.
            * ``carry_next_link`` — set when ``max_records`` capped the read
              mid-pagination; the caller persists this in the offset.
            * ``rebootstrap`` — True iff a 410 fired on a stored link; the
              caller re-issues from a fresh empty offset.
            """
            session = self._get_session()
            records: list[dict] = []
            new_delta_link: str | None = None
            carry_next_link: str | None = None
            page_index = 0
            bootstrap_verified = not is_bootstrap
            sparse_checked = False
            current_url: str | None = url

            while current_url:
                headers = initial_headers if (page_index == 0 and initial_headers) else None
                kwargs: dict[str, Any] = {"headers": headers} if headers else {}
                resp = self._http_get(session, current_url, **kwargs)
                if resp.status_code == 410 and (prev_delta_link or prev_next_link):
                    return [], None, None, True
                resp.raise_for_status()

                if not bootstrap_verified:
                    self._verify_delta_bootstrap(resp, table_name)
                    bootstrap_verified = True

                payload = resp.json()
                sparse_checked = self._delta_collect_page_records(
                    payload=payload,
                    records=records,
                    primary_keys=primary_keys,
                    table_name=table_name,
                    table_options=table_options,
                    sparse_checked=sparse_checked,
                    max_records=max_records,
                )
                current_url, new_delta_link, carry_next_link = self._delta_advance_links(
                    payload=payload,
                    resp_url=resp.url,
                    records=records,
                    max_records=max_records,
                    new_delta_link=new_delta_link,
                    carry_next_link=carry_next_link,
                )
                page_index += 1

            return records, new_delta_link, carry_next_link, False

        def _verify_delta_bootstrap(self, resp: requests.Response, table_name: str) -> None:
            """Confirm the server actually honored ``Prefer: odata.track-changes``."""
            applied = resp.headers.get("Preference-Applied", "")
            if _DELTA_PREFER not in applied.lower():
                raise RuntimeError(
                    f"OData server did not honor 'Prefer: odata.track-changes' "
                    f"for {table_name!r} (response missing 'Preference-Applied' "
                    f"header). The probe in delta_tracking=auto should have "
                    f"caught this — your service may have inconsistent support. "
                    f"Set delta_tracking=disabled and use cursor-based "
                    f"incremental instead."
                )

        def _delta_collect_page_records(
            self,
            *,
            payload: dict,
            records: list[dict],
            primary_keys: list[str],
            table_name: str,
            table_options: dict[str, str] | None,
            sparse_checked: bool,
            max_records: int,
        ) -> bool:
            """Append delta records from ``payload`` until cap or page exhaustion.

            Returns the updated ``sparse_checked`` flag so the caller can
            continue to skip the check on later pages once it's already
            passed for this call.
            """
            for item in payload.get("value", []):
                if not sparse_checked and "@removed" not in item:
                    self._check_no_sparse_entity(item, table_name, table_options)
                    sparse_checked = True
                records.append(self._build_delta_record(item, primary_keys))
                if len(records) >= max_records:
                    break
            return sparse_checked

        def _delta_advance_links(
            self,
            *,
            payload: dict,
            resp_url: str,
            records: list[dict],
            max_records: int,
            new_delta_link: str | None,
            carry_next_link: str | None,
        ) -> tuple[str | None, str | None, str | None]:
            """Resolve the next URL + offset bookkeeping after one page.

            Returns ``(next_url, new_delta_link, carry_next_link)``.
            ``next_url`` is ``None`` when pagination should stop (either we
            hit the cap, saw a terminal deltaLink, or the server omitted
            both pagination links).
            """
            raw_delta = payload.get("@odata.deltaLink")
            raw_next = payload.get("@odata.nextLink")
            cap_hit = len(records) >= max_records

            if cap_hit:
                if raw_next:
                    carry_next_link = urljoin(resp_url, raw_next)
                # Capture the deltaLink even on a cap-hit page — when the
                # cap lines up exactly with the terminal page we still want
                # the next-batch resume to follow ``delta_link`` rather
                # than re-walk the whole bootstrap.
                if raw_delta and new_delta_link is None:
                    new_delta_link = urljoin(resp_url, raw_delta)
                return None, new_delta_link, carry_next_link

            if raw_delta:
                new_delta_link = urljoin(resp_url, raw_delta)
                return None, new_delta_link, carry_next_link
            if raw_next:
                return urljoin(resp_url, raw_next), new_delta_link, carry_next_link
            return None, new_delta_link, carry_next_link

        def _check_no_sparse_entity(
            self,
            item: dict,
            table_name: str,
            table_options: dict[str, str] | None,
        ) -> None:
            """Refuse silently-corrupting sparse delta responses.

            OData v4 §11.4 lets a delta payload return only the *changed*
            properties on an updated entity. That sounds harmless until you
            realize the connector emits the dict as-is to Spark, which
            treats absent fields as NULL — overwriting good destination
            values with nulls on every partial update. The damage is silent
            and not recoverable from the destination table alone.

            We can't safely apply partial updates in v1, so refuse them up
            front with an actionable error. Run only on the first
            non-tombstone entry per call.

            The expected key set is the declared schema for the table, less
            any selection imposed by ``$select`` and less the synthetic
            ``_deleted`` / ``_lc_sequence`` columns we add ourselves.
            """
            select = (table_options or {}).get("select")
            if select:
                expected = {c.strip() for c in select.split(",") if c.strip()}
            else:
                namespace = (table_options or {}).get("namespace")
                expected = {f.name for f in self._fields_for(table_name, namespace)}
            expected -= {_DELETED_COL, _SEQUENCE_COL}
            actual = {k for k in item.keys() if not k.startswith("@odata.")}
            missing = expected - actual
            if missing:
                raise RuntimeError(
                    f"OData delta response for {table_name!r} returned a sparse "
                    f"entity: missing properties {sorted(missing)}. The connector "
                    f"cannot safely apply partial updates — every missing field "
                    f"would write NULL at the destination, silently corrupting "
                    f"data. Set delta_tracking=disabled to use cursor-based "
                    f"incremental, or restrict the schema with $select to only "
                    f"the fields the server always returns in delta payloads."
                )

        # ------------------------------------------------------------------
        # Delta tracking capability
        # ------------------------------------------------------------------

        def _delta_setting(self, table_options: dict[str, str] | None) -> str:
            """Resolve the delta_tracking option, normalised to lower case.

            Defaults to ``disabled``. Delta tracking is opt-in because most
            OData services don't honor ``Prefer: odata.track-changes``, and
            a default-``auto`` would burn one wasted HTTP probe per table
            per pipeline trigger on the common case where the user doesn't
            want this feature anyway.
            """
            raw = ((table_options or {}).get("delta_tracking") or "disabled").strip().lower()
            if raw not in {"auto", "enabled", "disabled"}:
                raise ValueError(
                    f"Invalid delta_tracking={raw!r}. Expected one of: auto, enabled, disabled."
                )
            return raw

        def _delta_cache_key(
            self, table_name: str, table_options: dict[str, str] | None
        ) -> tuple[str, str]:
            """Cache key for :py:attr:`_delta_capable` keyed on (namespace, table).

            Namespace defaults to the empty string when omitted so multi-schema
            services with a single un-namespaced declaration also key cleanly.
            """
            namespace = (table_options or {}).get("namespace") or ""
            return (namespace, table_name)

        def _delta_active_for(self, table_name: str, table_options: dict[str, str] | None) -> bool:
            """Whether delta tracking is the read mode for this table.

            Resolution order:
              1. ``delta_tracking=disabled`` → never.
              2. ``cursor_field`` set + ``delta_tracking=enabled`` → ValueError
                 (the two are mutually exclusive — delta tracking provides
                 its own sequencing).
              3. ``cursor_field`` set + ``delta_tracking=auto`` → cursor wins;
                 delta is left dormant, no probe.
              4. ``delta_tracking=enabled`` → assume support; a probe failure
                 surfaces at read time rather than here.
              5. ``delta_tracking=auto`` → probe once, cache, decide.
            """
            setting = self._delta_setting(table_options)
            if setting == "disabled":
                return False
            if (table_options or {}).get("cursor_field"):
                if setting == "enabled":
                    raise ValueError(
                        "delta_tracking=enabled is mutually exclusive with "
                        "cursor_field; the server-driven delta stream provides "
                        "its own sequencing. Remove cursor_field, or switch to "
                        "delta_tracking=disabled to use cursor-based incremental."
                    )
                return False
            if setting == "enabled":
                return True
            key = self._delta_cache_key(table_name, table_options)
            if key not in self._delta_capable:
                self._delta_capable[key] = self._probe_delta_support(table_name, table_options)
            return self._delta_capable[key]

        def _probe_delta_support(self, table_name: str, table_options: dict[str, str] | None) -> bool:
            """Light-touch capability probe.

            Sends a small GET against the entity set with the
            ``Prefer: odata.track-changes`` header and inspects the response
            headers for ``Preference-Applied: odata.track-changes``. That
            header is the spec's positive acknowledgement that the server is
            honoring change tracking on this request.

            Returns ``False`` for every failure mode (non-200, missing
            header, malformed body, network error). The cache is populated
            with that ``False`` so we don't retry the probe per call — the
            connector falls back to whatever cursor/snapshot path the
            user's options imply.
            """
            # Force ``$top=1`` for the probe so the response stays small even
            # against entity sets with millions of rows. We only care about
            # headers.
            probe_options = {**(table_options or {}), "page_size": "1"}
            url = self._build_url(table_name, probe_options)
            try:
                session = self._get_session()
                resp = self._http_get(
                    session,
                    url,
                    headers={"Prefer": _DELTA_PREFER},
                )
            except (requests.RequestException, ValueError, RuntimeError, PermissionError):
                return False
            if resp.status_code != 200:
                return False
            applied = resp.headers.get("Preference-Applied", "")
            return _DELTA_PREFER in applied.lower()

        # ------------------------------------------------------------------
        # URL + HTTP plumbing
        # ------------------------------------------------------------------

        def _build_url(
            self,
            table_name: str,
            table_options: dict[str, str],
            extra_filter: str | None = None,
            order_by: str | None = None,
        ) -> str:
            base = _join_url(self.service_url, table_name)
            return f"{base}?{self._format_query_params(table_options, extra_filter, order_by)}"

        def _format_query_params(
            self,
            table_options: dict[str, str],
            extra_filter: str | None = None,
            order_by: str | None = None,
        ) -> str:
            """Compose $top/$select/$filter/$orderby; shared across all URL builders."""
            opts = table_options or {}
            params = [f"$top={opts.get('page_size', '1000')}"]
            if opts.get("select"):
                params.append(f"$select={opts['select']}")
            filters = [f for f in (opts.get("filter"), extra_filter) if f]
            if filters:
                params.append(f"$filter={' and '.join(f'({f})' for f in filters)}")
            if order_by:
                params.append(f"$orderby={order_by}")
            return "&".join(params)

        def _fetch_pages(self, url: str) -> Iterator[dict]:
            """Walk @odata.nextLink, yielding raw JSON dicts (no coercion).

            The OData v4 spec allows @odata.nextLink to be either an absolute
            URL or a relative one (resolved against the request URL). Some
            services (e.g. SAP NetWeaver Gateway, certain self-hosted Olingo
            deployments) return just ``Customers?$skiptoken=...`` and rely on
            the client to prepend the service root. urljoin handles both
            cases — absolutes pass through unchanged.
            """
            for page_rows, _ in self._fetch_pages_with_links(url):
                yield from page_rows

        def _fetch_pages_with_links(self, url: str) -> Iterator[tuple[list[dict], str | None]]:
            """Page-aware variant of ``_fetch_pages``: yields
            ``(page_rows, next_url)`` for each HTTP response.

            Lets callers checkpoint at page boundaries — the yielded
            ``next_url`` is the resolved @odata.nextLink (or ``None`` when
            the chain is exhausted). Resuming from that link on a later
            call hands the server back its own opaque skiptoken; the server
            picks up exactly where it left off without the caller needing
            to reconstruct ``$filter``/``$orderby``/``$select`` state.
            """
            session = self._get_session()
            next_url: str | None = url
            while next_url:
                resp = self._http_get(session, next_url)
                resp.raise_for_status()
                payload = resp.json()
                page_rows = [
                    {k: v for k, v in item.items() if not k.startswith("@odata.")}
                    for item in payload.get("value", [])
                ]
                raw_next = payload.get("@odata.nextLink")
                new_next = urljoin(resp.url, raw_next) if raw_next else None
                yield page_rows, new_next
                next_url = new_next

        def _http_get(self, session: requests.Session, url: str, **kwargs: Any) -> requests.Response:
            """GET with auth-aware 401/403 handling.

            Three layers, escalating in cost:

            1. **Pre-emptive refresh** — when the token endpoint gave us
               ``expires_in`` and we're past the recorded deadline (with a
               60 s safety buffer), swap the bearer header *before* sending
               the request. Avoids a wasted round-trip on long-running
               paginated reads that straddle an expiry boundary.
            2. **Reactive refresh** — caught 401 from the source, OAuth
               refresh path is available → mint a fresh token and retry
               once. A second 401 here means the access token is fine but
               the principal lacks read access (different error path).
            3. **Actionable no-refresh-path failure** — 401 or 403 from
               the source and no automatic refresh is configured (bearer,
               basic, api_key, or OAuth without a refresh-issuing token
               endpoint). Raise a :class:`PermissionError` whose message
               names the specific connection options the operator should
               check for the configured auth mode. ``requests.HTTPError``
               with no context is too opaque to triage from a pipeline log.
            """
            if self._should_preemptively_refresh():
                session.headers["Authorization"] = f"Bearer {self._oauth2_token()}"
            resp = session.get(url, timeout=self.timeout, **kwargs)
            if resp.status_code == 401 and self._has_oauth_refresh_path():
                session.headers["Authorization"] = f"Bearer {self._oauth2_token()}"
                resp = session.get(url, timeout=self.timeout, **kwargs)
                if resp.status_code == 401:
                    # We just minted a token straight from the OAuth provider
                    # and the source still rejected it — the access token isn't
                    # the problem. Most likely the principal lacks read access
                    # to this entity set, the scope is insufficient, or the
                    # tenant is mis-mapped. Surface that explicitly so the user
                    # doesn't chase a non-existent token issue.
                    raise PermissionError(
                        f"OData service returned 401 for {url!r} even after "
                        f"refreshing the OAuth2 access token. The new token "
                        f"reached the server, so the access token itself is "
                        f"not the problem. Check that the OAuth principal has "
                        f"read access to this entity set, that 'oauth2_scope' "
                        f"grants the right permissions, and that any "
                        f"tenant/instance identifier in 'service_url' or "
                        f"'extra_headers' matches the credentials. Server "
                        f"response: {_truncate(resp.text, 300)}"
                    )
                return resp
            if resp.status_code in (401, 403):
                raise PermissionError(self._no_refresh_auth_error(resp, url))
            return resp

        def _no_refresh_auth_error(self, resp: requests.Response, url: str) -> str:
            """Construct an actionable auth-failure message for the no-refresh path.

            Different auth modes have very different failure modes — bearer
            tokens expire, OAuth scopes can be too narrow, basic creds rot —
            and bundling them all into one generic "401 Unauthorized" makes
            triage from a pipeline log nearly impossible. This method picks
            the relevant remediation hints based on which auth mode is
            active on the connection.
            """
            status = resp.status_code
            body = _truncate(resp.text, 300) or "(empty body)"
            auth = (self.options.get("auth_type") or "").lower().strip()
            if not auth and self.options.get("token"):
                auth = "bearer"
            prefix = (
                f"OData service returned {status} for {url!r} and no "
                f"automatic token-refresh path is configured. "
            )
            if auth == "bearer":
                return (
                    f"{prefix}"
                    f"With auth_type=bearer the pre-acquired access token cannot "
                    f"be refreshed by the connector — either it has expired "
                    f"(typical lifetime ~1 h), or the principal that issued it "
                    f"lacks read access to this entity set. Fixes: replace "
                    f"'token' on the connection with a fresh one; or switch to "
                    f"auth_type=oauth2 with 'oauth2_client_id' + "
                    f"'oauth2_client_secret' so the connector mints and "
                    f"refreshes tokens automatically. For Microsoft Graph "
                    f"high-privilege endpoints (identityProviders, auditLogs, "
                    f"etc.), ensure the token carries the required scope and "
                    f"admin consent. Server response: {body}"
                )
            if auth == "basic":
                return (
                    f"{prefix}"
                    f"With auth_type=basic the credentials are sent on every "
                    f"request unchanged. Check 'username' and 'password' on "
                    f"the connection — the password may have expired or been "
                    f"rotated — and confirm the user has read access to this "
                    f"entity set at the source. Server response: {body}"
                )
            if auth == "api_key":
                return (
                    f"{prefix}"
                    f"With auth_type=api_key the key is sent on every request "
                    f"unchanged. Check 'api_key' (may have been rotated or "
                    f"revoked) and 'api_key_header' (some services expect a "
                    f"non-default header name). Confirm the key's scope "
                    f"includes this entity set. Server response: {body}"
                )
            if auth == "oauth2":
                return (
                    f"{prefix}"
                    f"With auth_type=oauth2 but no refresh path available "
                    f"(missing 'oauth2_client_id' / 'oauth2_client_secret' "
                    f"for client-credentials, and no 'oauth2_refresh_token' "
                    f"for user-flow refresh), the connector can't mint a "
                    f"fresh access token. Provide one of those pairs, or "
                    f"replace 'oauth2_access_token' with a fresh value. "
                    f"Also confirm 'oauth2_scope' grants read on this entity "
                    f"set. Server response: {body}"
                )
            return (
                f"{prefix}"
                f"No authentication is configured on this connection but the "
                f"OData service requires it. Set 'auth_type' to one of: "
                f"bearer, basic, api_key, oauth2 (with the matching parameter "
                f"set). Server response: {body}"
            )

        def _should_preemptively_refresh(self) -> bool:
            """True iff a known-expiry token has hit its 60 s safety window."""
            if self._access_token_expires_at is None:
                return False
            return time.monotonic() >= self._access_token_expires_at

        def _has_oauth_refresh_path(self) -> bool:
            """True iff `_oauth2_token()` can mint a fresh access token.

            Either a refresh token is on hand (user flow) or
            ``oauth2_client_id`` + ``oauth2_client_secret`` are present
            for the client-credentials grant.
            """
            if self.options.get("oauth2_refresh_token"):
                return True
            return bool(
                self.options.get("oauth2_client_id") and self.options.get("oauth2_client_secret")
            )

        # ------------------------------------------------------------------
        # Auth session
        # ------------------------------------------------------------------

        def _get_session(self) -> requests.Session:
            if self._session is not None:
                return self._session

            session = requests.Session()
            session.headers.update(
                {
                    "Accept": "application/json",
                    "OData-Version": "4.0",
                    "OData-MaxVersion": "4.0",
                }
            )
            extra_headers = self.options.get("extra_headers")
            if extra_headers:
                for pair in extra_headers.split(","):
                    if ":" in pair:
                        k, v = pair.split(":", 1)
                        session.headers[k.strip()] = v.strip()

            auth_type = (self.options.get("auth_type") or "").lower().strip()
            if not auth_type and self.options.get("token"):
                auth_type = "bearer"

            if auth_type == "bearer":
                session.headers["Authorization"] = f"Bearer {_require(self.options, 'token')}"
            elif auth_type == "basic":
                from requests.auth import HTTPBasicAuth

                session.auth = HTTPBasicAuth(
                    _require(self.options, "username"),
                    _require(self.options, "password"),
                )
            elif auth_type == "api_key":
                header = self.options.get("api_key_header", "x-api-key")
                session.headers[header] = _require(self.options, "api_key")
            elif auth_type == "oauth2":
                # Two sub-modes share this branch:
                #  * **User flow** — `oauth2_refresh_token` is set. A
                #    pre-supplied `oauth2_access_token` is used as-is if
                #    present (avoids an unnecessary round-trip); otherwise
                #    `_oauth2_token()` runs the refresh-token grant to
                #    mint one. Expired tokens mid-run are caught in
                #    `_http_get` and refreshed once.
                #  * **Client-credentials flow** — no refresh token; the
                #    connector mints a fresh access token via
                #    `client_credentials` at session start.
                initial_token = self.options.get("oauth2_access_token") or self._oauth2_token()
                session.headers["Authorization"] = f"Bearer {initial_token}"
            elif auth_type:
                raise ValueError(
                    f"Unknown auth_type {auth_type!r}. "
                    f"Expected one of: bearer, basic, api_key, oauth2."
                )

            self._session = session
            return session

        def _oauth2_token(self) -> str:
            """Mint an OAuth2 access token.

            Picks the grant type from what's available in `self.options`:
              * `oauth2_refresh_token` present -> `refresh_token` grant
                (user-flow refresh). Client id/secret are required so the
                token endpoint can authenticate the client.
              * Otherwise -> `client_credentials` grant (server-to-server).

            Some providers issue a rotated refresh token in the response;
            when that happens, the new value is written back into
            `self.options` so the next refresh uses it.
            """
            refresh_token = self.options.get("oauth2_refresh_token")
            if refresh_token:
                data = {
                    "grant_type": "refresh_token",
                    "refresh_token": refresh_token,
                    "client_id": _require(self.options, "oauth2_client_id"),
                    "client_secret": _require(self.options, "oauth2_client_secret"),
                }
            else:
                data = {
                    "grant_type": "client_credentials",
                    "client_id": _require(self.options, "oauth2_client_id"),
                    "client_secret": _require(self.options, "oauth2_client_secret"),
                }
            scope = self.options.get("oauth2_scope")
            if scope:
                data["scope"] = scope
            resp = requests.post(
                _require(self.options, "oauth2_token_url"),
                data=data,
                timeout=self.timeout,
            )
            # Surface a precise, actionable error when the token endpoint
            # itself rejects the request. raise_for_status() would otherwise
            # produce a terse "401 Client Error: Unauthorized for url ..."
            # that doesn't tell the user *which* credential is the problem.
            if resp.status_code in (400, 401):
                grant = data["grant_type"]
                hint = _extract_oauth_error_hint(resp)
                if grant == "refresh_token":
                    raise ValueError(
                        f"OAuth2 token endpoint returned {resp.status_code} when "
                        f"refreshing the access token. The refresh token may be "
                        f"expired, revoked, or paired with a different OAuth "
                        f"client. Check that 'oauth2_refresh_token' was issued by "
                        f"the same 'oauth2_client_id' configured on this "
                        f"connection, and re-run the authorization-code flow if "
                        f"needed. Server response: {hint}"
                    ) from None
                raise ValueError(
                    f"OAuth2 token endpoint returned {resp.status_code} for the "
                    f"client_credentials grant. Check 'oauth2_client_id', "
                    f"'oauth2_client_secret', 'oauth2_token_url', and "
                    f"'oauth2_scope' on this connection. Server response: {hint}"
                ) from None
            resp.raise_for_status()
            payload = resp.json()
            token = payload.get("access_token")
            if not token:
                raise RuntimeError("OAuth2 token endpoint did not return access_token.")
            rotated_refresh = payload.get("refresh_token")
            if rotated_refresh:
                self.options["oauth2_refresh_token"] = rotated_refresh
            # Track wall-clock deadline so `_http_get` can refresh the token
            # *before* the source returns 401. Subtract a 60 s safety margin
            # to cover clock skew + in-flight request latency. Absent
            # `expires_in` means the provider didn't tell us — fall back to
            # the lazy 401-retry path.
            expires_in = payload.get("expires_in")
            if expires_in is not None:
                try:
                    self._access_token_expires_at = time.monotonic() + int(expires_in) - 60
                except (TypeError, ValueError):
                    self._access_token_expires_at = None
            else:
                self._access_token_expires_at = None
            return token

        # ------------------------------------------------------------------
        # $metadata caching + parsing
        # ------------------------------------------------------------------

        def _metadata_root(self) -> ET.Element:
            if self._metadata_xml is None:
                session = self._get_session()
                url = _join_url(self.service_url, "$metadata")
                resp = self._http_get(session, url, headers={"Accept": "application/xml"})
                resp.raise_for_status()
                self._metadata_xml = resp.text
            return ET.fromstring(self._metadata_xml)

        def _entity_set_index(self) -> list[tuple[str, str]]:
            """All (schema_namespace, entity_set_name) pairs declared in $metadata."""
            root = self._metadata_root()
            out: list[tuple[str, str]] = []
            for schema in root.iter(f"{_NS_EDM}Schema"):
                ns = schema.get("Namespace") or ""
                for container in schema.iter(f"{_NS_EDM}EntityContainer"):
                    for es in container.iter(f"{_NS_EDM}EntitySet"):
                        out.append((ns, es.get("Name")))
            return out

        def _entity_type_for(self, table_name: str, namespace: str | None = None) -> ET.Element:
            """Resolve flat names or contained paths (segment-by-segment via
            contained nav props on the base-type chain)."""
            segments = _parse_contained_path(table_name) or [table_name]
            et = self._flat_entity_type_for(segments[0], namespace)
            for idx, child_segment in enumerate(segments[1:], start=1):
                nav_props = self._all_contained_nav_props(et)
                target_ref = next((r for n, r in nav_props if n == child_segment), None)
                if target_ref is None:
                    walked = _CONTAINED_PATH_SEP.join(segments[:idx])
                    raise ValueError(
                        f"{child_segment!r} is not a contained-collection navigation "
                        f"property on {walked!r}. Available contained collections: "
                        f"{sorted(n for n, _ in nav_props)}"
                    )
                target_et = self._resolve_type_ref(target_ref)
                if target_et is None:
                    raise ValueError(
                        f"Contained navigation target {target_ref!r} (referenced by "
                        f"{child_segment!r} on {segments[idx - 1]!r}) not found in $metadata."
                    )
                et = target_et
            return et

        def _flat_entity_type_for(self, table_name: str, namespace: str | None = None) -> ET.Element:
            """Resolve a top-level entity-set name to its EntityType element."""
            root = self._metadata_root()
            matches: list[tuple[str, str]] = []
            for schema in root.iter(f"{_NS_EDM}Schema"):
                ns = schema.get("Namespace") or ""
                if namespace is not None and ns != namespace:
                    continue
                for container in schema.iter(f"{_NS_EDM}EntityContainer"):
                    for es in container.iter(f"{_NS_EDM}EntitySet"):
                        if es.get("Name") == table_name:
                            matches.append((ns, es.get("EntityType")))
            if not matches:
                available = self._entity_set_index()
                if namespace is not None:
                    hint = sorted({es for ns, es in available if ns == namespace})
                    if not hint:
                        # The requested namespace has zero entity sets — common
                        # confusion when the user picks a type-only schema
                        # (e.g. one declaring BaseType references) instead of
                        # the schema whose <EntityContainer> declares the sets.
                        others = sorted({ns for ns, _ in available if ns})
                        raise ValueError(
                            f"Entity set {table_name!r} not found in namespace "
                            f"{namespace!r}. Namespace {namespace!r} declares "
                            f"no entity sets (probably a type-only schema). "
                            f"Namespaces with entity sets: {others}."
                        )
                    raise ValueError(
                        f"Entity set {table_name!r} not found in namespace "
                        f"{namespace!r}. Available in this namespace: {hint}"
                    )
                raise ValueError(
                    f"Entity set {table_name!r} not found in $metadata. "
                    f"Available: {sorted({n for _, n in available})}"
                )
            if len(matches) > 1:
                namespaces = sorted({m[0] for m in matches})
                raise ValueError(
                    f"Entity set {table_name!r} is declared in multiple namespaces: "
                    f"{namespaces}. Set 'namespace' in table_options to disambiguate."
                )
            schema_ns, type_ref = matches[0]
            et = self._resolve_type_ref(type_ref)
            if et is None:
                raise ValueError(
                    f"EntityType {type_ref!r} (referenced by entity set "
                    f"{table_name!r} in schema {schema_ns!r}) not found in $metadata."
                )
            return et

        def _schema_alias_map(self) -> dict[str, str]:
            """Build {namespace_or_alias → actual_schema_namespace}.

            CSDL allows each ``<Schema>`` to declare both a ``Namespace`` and
            a shorter ``Alias``; downstream type references can use either.
            Microsoft Graph for instance declares
            ``Namespace="microsoft.graph" Alias="graph"`` and then writes
            ``BaseType="graph.directoryObject"``. We can't resolve those
            references without honoring the alias.
            """
            root = self._metadata_root()
            out: dict[str, str] = {}
            for schema in root.iter(f"{_NS_EDM}Schema"):
                ns = schema.get("Namespace") or ""
                if ns:
                    out[ns] = ns
                alias = schema.get("Alias")
                if alias:
                    out[alias] = ns
            return out

        def _resolve_type_ref(self, type_ref: str) -> ET.Element | None:
            """Find the ``<EntityType>`` element for a qualified type reference.

            Accepts both fully-qualified namespace references
            (``microsoft.graph.user``) and alias-based references
            (``graph.user``). Returns ``None`` if no matching declaration
            exists — callers decide whether that's a hard error or worth
            falling back to a shallower lookup.
            """
            if "." not in type_ref:
                return None
            prefix, type_name = type_ref.rsplit(".", 1)
            aliases = self._schema_alias_map()
            target_ns = aliases.get(prefix)
            if target_ns is None:
                return None
            root = self._metadata_root()
            for schema in root.iter(f"{_NS_EDM}Schema"):
                if schema.get("Namespace") != target_ns:
                    continue
                for et in schema.findall(f"{_NS_EDM}EntityType"):
                    if et.get("Name") == type_name:
                        return et
            return None

        def _resolve_base_chain(self, et: ET.Element) -> list[ET.Element]:
            """Walk the ``BaseType`` chain starting at ``et``.

            Returns ``[et, parent, grandparent, …]`` until ``BaseType`` is
            absent or unresolvable. OData v4 §8.4: derived entity types
            inherit Keys and Properties from their base. Real-world
            services (Microsoft Graph, Microsoft Dataverse, most SAP
            deployments) lean on this heavily — Graph's ``user`` extends
            ``directoryObject`` extends ``entity``, and ``entity`` is the
            type that actually declares ``<Key>id</Key>``.

            Cycles are guarded against (cyclic CSDL is malformed but won't
            crash the connector).
            """
            chain = [et]
            current = et
            seen: set[str] = set()
            while True:
                base_ref = current.get("BaseType")
                if not base_ref or base_ref in seen:
                    break
                seen.add(base_ref)
                parent = self._resolve_type_ref(base_ref)
                if parent is None:
                    break
                chain.append(parent)
                current = parent
            return chain

        def _fields_for(self, table_name: str, namespace: str | None = None) -> list[StructField]:
            segments = _parse_contained_path(table_name) or [table_name]
            own_fields = self._own_fields_for_et(self._entity_type_for(table_name, namespace))
            if len(segments) == 1:
                return own_fields
            # Every non-leaf ancestor contributes FK columns (OData v4
            # §13.4.3 — contained-entity keys are unique within parent only).
            fk_columns = self._resolve_fk_columns(segments, namespace)
            fk_fields: list[StructField] = []
            for idx in range(len(segments) - 1):
                seg = segments[idx]
                if not any(k[0] == seg for k in fk_columns):
                    continue
                ancestor_et = self._entity_type_for(
                    _CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace
                )
                own = {f.name: f.dataType for f in self._own_fields_for_et(ancestor_et)}
                for pk in self._own_primary_keys_for_et(ancestor_et):
                    fk_fields.append(
                        StructField(
                            fk_columns[(seg, pk)],
                            own.get(pk, StringType()),
                            False,
                        )
                    )
            return fk_fields + own_fields

        def _own_fields_for_et(self, et: ET.Element) -> list[StructField]:
            """Property fields on ``et`` and its base chain. Walks root → leaf
            so inherited fields appear before leaf's own additions; de-dupes
            by name with closest-to-root winning (spec forbids redeclaration)."""
            fields: list[StructField] = []
            seen: set[str] = set()
            for type_el in reversed(self._resolve_base_chain(et)):
                for prop in type_el.findall(f"{_NS_EDM}Property"):
                    name = prop.get("Name")
                    if name in seen:
                        continue
                    seen.add(name)
                    fields.append(
                        StructField(
                            name,
                            _EDM_TO_SPARK.get(prop.get("Type", "Edm.String"), StringType()),
                            prop.get("Nullable", "true").lower() != "false",
                        )
                    )
            return fields

        def _primary_keys_for(self, table_name: str, namespace: str | None = None) -> list[str]:
            segments = _parse_contained_path(table_name) or [table_name]
            leaf_pks = self._own_primary_keys_for_et(self._entity_type_for(table_name, namespace))
            if len(segments) == 1:
                return leaf_pks
            # Composite: every ancestor's FK columns + leaf's own PKs.
            fk_columns = self._resolve_fk_columns(segments, namespace)
            composite: list[str] = []
            for idx in range(len(segments) - 1):
                seg = segments[idx]
                if not any(k[0] == seg for k in fk_columns):
                    continue
                ancestor_et = self._entity_type_for(
                    _CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace
                )
                for pk in self._own_primary_keys_for_et(ancestor_et):
                    composite.append(fk_columns[(seg, pk)])
            composite.extend(leaf_pks)
            return composite

        def _own_primary_keys_for_et(self, et: ET.Element) -> list[str]:
            """Primary-key property names (OData v4 §8.4: derived types inherit
            Keys; closest-to-leaf Key wins where multiple levels redeclare)."""
            for type_el in self._resolve_base_chain(et):
                key = type_el.find(f"{_NS_EDM}Key")
                if key is not None:
                    return [ref.get("Name") for ref in key.findall(f"{_NS_EDM}PropertyRef")]
            return []

        # ------------------------------------------------------------------
        # Cursor filter formatting
        # ------------------------------------------------------------------

        def _cursor_filter(self, cursor_field: str, since: Any) -> str | None:
            """Build the `$filter` clause for an incremental fetch.

            Strict `cursor gt since` once the offset has advanced; `None` on
            the very first call so the server returns the natural start of
            the table. `max_records_per_batch` is the per-call cap — there
            is no wall-clock ceiling, which is what makes continuous polling
            work and what keeps the connector type-agnostic over the cursor
            column.
            """
            if since is None:
                return None
            return f"{cursor_field} gt {_odata_literal(since)}"


    # ---------------------------------------------------------------------------
    # Helpers (module-level, no class state — easier to unit-test)
    # ---------------------------------------------------------------------------


    def _trim_to_distinct_cursor_boundary(
        records: list[dict],
        cursor_field: str,
    ) -> list[dict]:
        """Drop trailing records that share the boundary cursor value.

        Walks back from the tail until the cursor value changes, leaving a clean
        boundary that the next call's ``cursor gt <last>`` filter will pick up
        cleanly. Drops the boundary record itself — we can't tell whether the
        next page (or a concurrent insert before the next call) holds more
        records sharing that cursor value, so we surrender the whole group and
        let `cursor gt <prev_distinct>` re-fetch them.

        Returns an empty list when every record shares one cursor value; the
        caller decides whether that's recoverable (natural exhaustion) or a hard
        failure (truncated batch with too-small cap).
        """
        boundary = records[-1].get(cursor_field)
        trim_idx = len(records)
        while trim_idx > 0 and records[trim_idx - 1].get(cursor_field) == boundary:
            trim_idx -= 1
        return records[:trim_idx]


    def _extract_oauth_error_hint(resp: requests.Response) -> str:
        """Pull the most informative error description out of an OAuth2 response.

        Token endpoints conventionally return JSON with ``error`` (machine code,
        e.g. ``invalid_grant``) and often ``error_description`` (human-readable).
        Fall back to the raw body when the response isn't JSON, and truncate so
        we never dump a 50 KB error page into a user-facing message.
        """
        try:
            payload = resp.json()
        except ValueError:
            return _truncate(resp.text, 300) or "Unauthorized"
        if isinstance(payload, dict):
            description = payload.get("error_description")
            code = payload.get("error")
            if description and code:
                return f"{code}: {description}"
            if description:
                return str(description)
            if code:
                return str(code)
        return _truncate(resp.text, 300) or "Unauthorized"


    def _truncate(text: str, limit: int) -> str:
        """Cap a string at ``limit`` chars with a trailing ellipsis when clipped."""
        if text is None:
            return ""
        if len(text) <= limit:
            return text
        return text[:limit] + "..."


    def _require(options: dict[str, str], key: str) -> str:
        val = options.get(key)
        if not val:
            raise ValueError(f"Required option {key!r} is missing.")
        return val


    # Re-export base64/binary helper for any downstream caller that wants
    # to materialize Edm.Binary fields into Python bytes prior to Spark.
    def _decode_binary(value: str) -> bytes:
        return base64.b64decode(value)


    _CONTAINED_PATH_SEP = CONTAINED_PATH_SEP
    _join_url = join_url
    _odata_literal = odata_literal
    _parse_contained_path = parse_contained_path


    ########################################################
    # src/databricks/labs/community_connector/sparkpds/lakeflow_datasource.py
    ########################################################

    LakeflowConnectImpl = ODataLakeflowConnect
    # Constant option or column names
    METADATA_TABLE = "_community_table_metadata"
    NAMESPACES_TABLE = "_community_namespaces"
    TABLES_TABLE = "_community_tables"
    VIRTUAL_TABLES = (METADATA_TABLE, NAMESPACES_TABLE, TABLES_TABLE)
    TABLE_NAME = "tableName"
    TABLE_NAME_LIST = "tableNameList"
    TABLE_CONFIGS = "tableConfigs"
    IS_DELETE_FLOW = "isDeleteFlow"
    NAMESPACE_PREFIX = "namespacePrefix"
    NAMESPACE = "namespace"


    def _decode_list_of_str_option(option_name: str, value: str | None) -> list[str] | None:
        """Decode and validate a JSON-encoded ``list[str]`` Spark option.

        Returns ``None`` if the option is absent; otherwise the parsed list.
        Raises ``ValueError`` with the offending value if the JSON is malformed
        or the decoded value is not a list of strings.
        """
        if value is None:
            return None
        try:
            decoded = json.loads(value)
        except json.JSONDecodeError as e:
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded list[str]; "
                f"got non-JSON value: {value!r}"
            ) from e
        if not isinstance(decoded, list) or not all(isinstance(s, str) for s in decoded):
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded list[str]; "
                f"got: {decoded!r}"
            )
        return decoded


    def _decode_dict_option(option_name: str, value: str | None) -> dict:
        """Decode and validate a JSON-encoded ``dict`` Spark option."""
        if value is None:
            return {}
        try:
            decoded = json.loads(value)
        except json.JSONDecodeError as e:
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded dict; "
                f"got non-JSON value: {value!r}"
            ) from e
        if not isinstance(decoded, dict):
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded dict; got: {decoded!r}"
            )
        return decoded


    # PySpark's DataSource API requires camelCase method names and inherits
    # semantics from the parent class, so per-method docstrings are redundant.
    # pylint: disable=invalid-name,missing-function-docstring
    class LakeflowStreamReader(SimpleDataSourceStreamReader, SupportsTriggerAvailableNow):
        """
        Implements a data source stream reader for Lakeflow Connect.
        Currently, only the simpleStreamReader is implemented, which uses a
        more generic protocol suitable for most data sources that support
        incremental loading.
        """

        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.lakeflow_connect = lakeflow_connect
            self.schema = schema

        def initialOffset(self):
            return {}

        def read(self, start: dict) -> (Iterator[tuple], dict):
            is_delete_flow = self.options.get(IS_DELETE_FLOW) == "true"
            # Strip delete flow options before passing to connector
            table_options = {
                k: v for k, v in self.options.items() if k != IS_DELETE_FLOW
            }

            if is_delete_flow:
                records, offset = self.lakeflow_connect.read_table_deletes(
                    self.options[TABLE_NAME], start, table_options
                )
            else:
                records, offset = self.lakeflow_connect.read_table(
                    self.options[TABLE_NAME], start, table_options
                )
            rows = map(lambda x: parse_value(x, self.schema), records)
            return rows, offset

        def readBetweenOffsets(self, start: dict, end: dict) -> Iterator[tuple]:
            # TODO: This does not ensure the records returned are identical across repeated calls.
            # For append-only tables, the data source must guarantee that reading from the same
            # start offset will always yield the same set of records.
            # For tables ingested as incremental CDC, it is only necessary that no new changes
            # are missed in the returned records.
            return self.read(start)[0]

        def prepareForTriggerAvailableNow(self) -> None:
            # No need to do anything special here. Everything is handled in the __init__ method.
            pass


    class LakeflowPartitionedStreamReader(DataSourceStreamReader, SupportsTriggerAvailableNow):
        """Proxy that bridges SupportsPartitionedStream to PySpark's DataSourceStreamReader.

        Used when a connector implements the SupportsPartitionedStream mixin to
        support partitioned streaming reads across Spark executors.
        """

        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.schema = schema
            self.lakeflow_connect = lakeflow_connect
            self.table_name = options[TABLE_NAME]
            self.table_options = {k: v for k, v in options.items() if k != IS_DELETE_FLOW}

        def initialOffset(self):
            return {}

        def getDefaultReadLimit(self):
            # Admission control is the connector's responsibility (e.g. via
            # window_days, max_records_per_batch), not the engine's.  Always
            # ask the engine for ReadAllAvailable.
            return ReadAllAvailable()

        def latestOffset(self, start: dict, limit) -> dict:
            # We declared ReadAllAvailable via getDefaultReadLimit; the engine
            # must respect it.  Anything else means admission-control expectations
            # we do not support — fail loudly rather than silently ignore.
            if not isinstance(limit, ReadAllAvailable):
                raise ValueError(
                    f"LakeflowPartitionedStreamReader only supports ReadAllAvailable; "
                    f"got {type(limit).__name__}. Micro-batch sizing must be controlled "
                    f"by the connector implementation (table_options), not the engine."
                )
            return self.lakeflow_connect.latest_offset(
                self.table_name, self.table_options, start
            )

        def partitions(self, start: dict, end: dict):
            partition_descs = self.lakeflow_connect.get_partitions(
                self.table_name, self.table_options, start, end
            )
            return [InputPartition(json.dumps(p)) for p in partition_descs]

        def read(self, partition: InputPartition):
            partition_desc = json.loads(partition.value)
            records = self.lakeflow_connect.read_partition(
                self.table_name, partition_desc, self.table_options
            )
            return map(lambda x: parse_value(x, self.schema), records)

        def prepareForTriggerAvailableNow(self) -> None:
            # No need to do anything special here. Everything is handled in the __init__ method.
            pass


    class LakeflowBatchReader(DataSourceReader):
        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.schema = schema
            self.lakeflow_connect = lakeflow_connect
            self.table_name = options[TABLE_NAME]
            self._supports_partition = isinstance(lakeflow_connect, SupportsPartition)

        def partitions(self):
            if self._supports_partition and self.table_name not in VIRTUAL_TABLES:
                try:
                    partition_descs = self.lakeflow_connect.get_partitions(
                        self.table_name, self.options
                    )
                    return [InputPartition(json.dumps(p)) for p in partition_descs]
                except Exception:
                    self._supports_partition = False
            return [InputPartition(None)]

        def read(self, partition):
            if self.table_name == METADATA_TABLE:
                records = self._read_table_metadata()
            elif self.table_name == NAMESPACES_TABLE:
                records = self._read_namespaces()
            elif self.table_name == TABLES_TABLE:
                records = self._read_tables()
            elif self._supports_partition and partition.value is not None:
                partition_desc = json.loads(partition.value)
                records = self.lakeflow_connect.read_partition(
                    self.table_name, partition_desc, self.options
                )
            else:
                records, _ = self.lakeflow_connect.read_table(self.table_name, None, self.options)
            return map(lambda x: parse_value(x, self.schema), records)

        def _read_table_metadata(self):
            table_names = _decode_list_of_str_option(
                TABLE_NAME_LIST, self.options.get(TABLE_NAME_LIST)
            ) or []
            table_configs = _decode_dict_option(
                TABLE_CONFIGS, self.options.get(TABLE_CONFIGS)
            )
            all_records = []
            # Preserve caller-supplied table order — caller controls it.
            for table in table_names:
                metadata = self.lakeflow_connect.read_table_metadata(
                    table, table_configs.get(table, {})
                )
                all_records.append({TABLE_NAME: table, **metadata})
            return all_records

        def _read_namespaces(self):
            # Connectors without SupportsNamespaces are flat — no rows.
            if not isinstance(self.lakeflow_connect, SupportsNamespaces):
                return []
            prefix = _decode_list_of_str_option(
                NAMESPACE_PREFIX, self.options.get(NAMESPACE_PREFIX)
            )
            namespaces = self.lakeflow_connect.list_namespaces(prefix)
            # Sort framework-side for deterministic output regardless of
            # connector iteration order.
            return [{"namespace": ns} for ns in sorted(namespaces)]

        def _read_tables(self):
            namespace_supplied = NAMESPACE in self.options
            if isinstance(self.lakeflow_connect, SupportsNamespaces):
                if not namespace_supplied:
                    raise ValueError(
                        f"option '{NAMESPACE}' is required when reading "
                        f"'{TABLES_TABLE}' against a connector that implements "
                        f"SupportsNamespaces. Pass a JSON-encoded list[str] "
                        f"(use '[]' for root-level tables; walk the tree via "
                        f"'{NAMESPACES_TABLE}' to enumerate every namespace)."
                    )
                namespace = _decode_list_of_str_option(
                    NAMESPACE, self.options[NAMESPACE]
                )
                tables = self.lakeflow_connect.list_tables_in_namespace(namespace)
                return [
                    {"namespace": namespace, TABLE_NAME: tn}
                    for tn in sorted(tables)
                ]
            # Flat connector path. Reject a stray `namespace` option — the
            # caller probably mistook this connector for namespace-aware and
            # silently ignoring the option would mask the bug.
            if namespace_supplied:
                raise ValueError(
                    f"option '{NAMESPACE}' was supplied but the connector does "
                    f"not implement SupportsNamespaces. Either omit the option "
                    f"or use a namespace-aware connector."
                )
            return [
                {"namespace": [], TABLE_NAME: tn}
                for tn in sorted(self.lakeflow_connect.list_tables())
            ]


    class LakeflowSource(DataSource):
        """
        PySpark DataSource implementation for Lakeflow Connect.
        """

        def __init__(self, options):
            self.options = options
            table = options.get(TABLE_NAME)
            # Catch typos against the framework's reserved virtual-table namespace
            # early — falling through to the connector with an unknown
            # `_community_*` name yields a confusing per-connector error.
            if table and table.startswith("_community_") and table not in VIRTUAL_TABLES:
                raise ValueError(
                    f"unknown framework virtual table '{table}'. Valid framework "
                    f"virtual tables are: {', '.join(VIRTUAL_TABLES)}. "
                    f"For a regular source table, use a name that does not start "
                    f"with '_community_'."
                )
            # TEMPORARY: LakeflowConnectImpl is replaced with the actual implementation
            # class during merge. See the placeholder comment at the top of this file.
            self.lakeflow_connect = LakeflowConnectImpl(options)  # pylint: disable=abstract-class-instantiated

        @classmethod
        def name(cls):
            return "lakeflow_connect"

        def schema(self):
            table = self.options[TABLE_NAME]
            if table == METADATA_TABLE:
                return StructType(
                    [
                        StructField(TABLE_NAME, StringType(), False),
                        StructField("primary_keys", ArrayType(StringType()), True),
                        StructField("cursor_field", StringType(), True),
                        StructField("ingestion_type", StringType(), True),
                    ]
                )
            if table == NAMESPACES_TABLE:
                return StructType(
                    [
                        StructField("namespace", ArrayType(StringType()), False),
                    ]
                )
            if table == TABLES_TABLE:
                return StructType(
                    [
                        StructField("namespace", ArrayType(StringType()), False),
                        StructField(TABLE_NAME, StringType(), False),
                    ]
                )
            return self.lakeflow_connect.get_table_schema(table, self.options)

        def reader(self, schema: StructType):
            return LakeflowBatchReader(self.options, schema, self.lakeflow_connect)

        def streamReader(self, schema: StructType):
            # Use the partitioned DataSourceStreamReader when the connector
            # implements SupportsPartitionedStream and the table opts in.
            # Otherwise, delegate to super() which raises PySparkNotImplementedError,
            # causing Spark to fall back to simpleStreamReader().
            if isinstance(self.lakeflow_connect, SupportsPartitionedStream):
                table = self.options[TABLE_NAME]
                if self.lakeflow_connect.is_partitioned(table):
                    return LakeflowPartitionedStreamReader(self.options, schema, self.lakeflow_connect)
            return super().streamReader(schema)

        def simpleStreamReader(self, schema: StructType):
            return LakeflowStreamReader(self.options, schema, self.lakeflow_connect)


    spark.dataSource.register(LakeflowSource)
